#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RendererCaps {
    pub backend_name: String,
    pub adapter_name: String,
    pub features: RendererFeatures,
    pub limits: RendererLimits,
    pub formats: FormatCaps,
}

impl Default for RendererCaps {
    fn default() -> Self {
        Self::for_backend(&RendererConfig::default(), "headless", "retained-api")
    }
}

impl RendererCaps {
    fn for_backend(config: &RendererConfig, backend_name: &str, adapter_name: &str) -> Self {
        let mut features = RendererFeatures::COMPUTE
            | RendererFeatures::INDIRECT_DRAW
            | RendererFeatures::STORAGE_TEXTURES
            | RendererFeatures::OCCLUSION_CULLING
            | RendererFeatures::FRAME_CAPTURE
            | RendererFeatures::EXTERNAL_FRAME_CAPTURE_HOOKS
            | RendererFeatures::DEBUG_DRAW
            | RendererFeatures::EDITOR_DEBUG_REPORTS
            | RendererFeatures::SKELETAL_ANIMATION
            | RendererFeatures::MORPH_TARGETS
            | RendererFeatures::LOD_SELECTION
            | RendererFeatures::MOTION_VECTORS
            | RendererFeatures::LIGHTS
            | RendererFeatures::SHADOW_MAPPING
            | RendererFeatures::ENVIRONMENT_IBL
            | RendererFeatures::RENDER_GRAPH
            | RendererFeatures::CUSTOM_RENDER_GRAPH_PASSES
            | RendererFeatures::STANDARD_3D_PIPELINE
            | RendererFeatures::PIPELINE_CACHE
            | RendererFeatures::SHADER_VARIANT_CACHE
            | RendererFeatures::BACKGROUND_RESOURCE_RETIREMENT
            | RendererFeatures::UPLOAD_QUEUE
            | RendererFeatures::RESOURCE_RESIDENCY
            | RendererFeatures::STREAMING_RESOURCES
            | RendererFeatures::DELAYED_RESOURCE_DESTROY
            | RendererFeatures::RESOURCE_LIFECYCLE
            | RendererFeatures::MESH_RESOURCES
            | RendererFeatures::BUFFER_RESOURCES
            | RendererFeatures::TEXTURE_RESOURCES
            | RendererFeatures::SAMPLER_RESOURCES
            | RendererFeatures::MATERIAL_SYSTEM
            | RendererFeatures::RETAINED_SCENE
            | RendererFeatures::CAMERA_VIEW_RENDER_TARGETS
            | RendererFeatures::ECS_EXTRACT_BOUNDARY;
        if config.gpu_profiling {
            features = features | RendererFeatures::TIMESTAMP_QUERY;
        }
        if cfg!(feature = "multi-draw-indirect") {
            features = features | RendererFeatures::MULTI_DRAW_INDIRECT;
        }
        if cfg!(feature = "pipeline-statistics") {
            features = features | RendererFeatures::PIPELINE_STATISTICS;
        }
        if cfg!(feature = "async-compute") {
            features = features | RendererFeatures::ASYNC_COMPUTE;
        }
        if cfg!(feature = "bindless") {
            features = features | RendererFeatures::BINDLESS_TEXTURES;
        }
        if cfg!(feature = "ray-tracing") {
            features = features | RendererFeatures::RAY_TRACING;
        }
        if cfg!(feature = "mesh-shader") {
            features = features | RendererFeatures::MESH_SHADER;
        }
        if cfg!(feature = "variable-rate-shading") {
            features = features | RendererFeatures::VARIABLE_RATE_SHADING;
        }
        if cfg!(feature = "gpu-driven") {
            features = features | RendererFeatures::GPU_DRIVEN_RENDERING;
        }
        if cfg!(feature = "virtual-texturing") {
            features = features | RendererFeatures::VIRTUAL_TEXTURING;
        }

        Self {
            backend_name: backend_name.to_owned(),
            adapter_name: adapter_name.to_owned(),
            features,
            limits: RendererLimits::default(),
            formats: FormatCaps::default(),
        }
    }
}

fn initial_gpu_profiler_enabled(config: &RendererConfig, caps: &RendererCaps) -> bool {
    config.gpu_profiling && caps.features.contains(RendererFeatures::TIMESTAMP_QUERY)
}

fn renderer_feature_tier(feature: RendererFeature) -> RendererFeatureTier {
    match feature {
        RendererFeature::Compute
        | RendererFeature::IndirectDraw
        | RendererFeature::StorageTextures
        | RendererFeature::OcclusionCulling
        | RendererFeature::ShaderReflection
        | RendererFeature::RenderGraph
        | RendererFeature::ResourceLifecycle
        | RendererFeature::MeshResources
        | RendererFeature::BufferResources
        | RendererFeature::TextureResources
        | RendererFeature::SamplerResources
        | RendererFeature::MaterialSystem
        | RendererFeature::RetainedScene
        | RendererFeature::CameraViewRenderTargets => RendererFeatureTier::Core,
        RendererFeature::BackendWgpu
        | RendererFeature::Surface
        | RendererFeature::TimestampQuery
        | RendererFeature::PipelineStatistics
        | RendererFeature::VertexAttribute64Bit
        | RendererFeature::BackgroundResourceRetirement
        | RendererFeature::NonblockingResourceRetirementPoll
        | RendererFeature::FrameCapture
        | RendererFeature::ExternalFrameCaptureHooks
        | RendererFeature::DebugDraw
        | RendererFeature::EditorDebugReports
        | RendererFeature::SkeletalAnimation
        | RendererFeature::MorphTargets
        | RendererFeature::LodSelection
        | RendererFeature::MotionVectors
        | RendererFeature::Lights
        | RendererFeature::ShadowMapping
        | RendererFeature::EnvironmentIbl
        | RendererFeature::CustomRenderGraphPasses
        | RendererFeature::Standard3dPipeline
        | RendererFeature::PipelineCache
        | RendererFeature::ShaderVariantCache
        | RendererFeature::UploadQueue
        | RendererFeature::ResourceResidency
        | RendererFeature::StreamingResources
        | RendererFeature::DelayedResourceDestroy
        | RendererFeature::EcsExtractBoundary => RendererFeatureTier::Optional,
        RendererFeature::MultiDrawIndirect
        | RendererFeature::BindlessTextures
        | RendererFeature::AsyncCompute
        | RendererFeature::RayTracing
        | RendererFeature::MeshShader
        | RendererFeature::VariableRateShading
        | RendererFeature::GpuDrivenRendering
        | RendererFeature::VirtualTexturing
        | RendererFeature::BackendGpuDeformation
        | RendererFeature::BackendIblConvolution
        | RendererFeature::BackendRealStandard3dPipeline
        | RendererFeature::CompleteBackendPipelineCache => RendererFeatureTier::Experimental,
        RendererFeature::BackendVulkan
        | RendererFeature::BackendMetal
        | RendererFeature::BackendD3d12
        | RendererFeature::NativeFrameDebuggerCapture => RendererFeatureTier::ReservedUnsupported,
    }
}

fn renderer_feature_implementation(feature: RendererFeature) -> RendererFeatureImplementation {
    match feature {
        RendererFeature::BackendWgpu
        | RendererFeature::Compute
        | RendererFeature::IndirectDraw
        | RendererFeature::StorageTextures
        | RendererFeature::Surface
        | RendererFeature::TimestampQuery
        | RendererFeature::VertexAttribute64Bit => RendererFeatureImplementation::BackendReal,
        RendererFeature::BackgroundResourceRetirement
        | RendererFeature::FrameCapture
        | RendererFeature::ExternalFrameCaptureHooks
        | RendererFeature::DebugDraw
        | RendererFeature::EditorDebugReports
        | RendererFeature::SkeletalAnimation
        | RendererFeature::MorphTargets
        | RendererFeature::LodSelection
        | RendererFeature::PipelineCache
        | RendererFeature::ShaderVariantCache
        | RendererFeature::UploadQueue
        | RendererFeature::ResourceResidency
        | RendererFeature::StreamingResources
        | RendererFeature::DelayedResourceDestroy
        | RendererFeature::ResourceLifecycle
        | RendererFeature::MeshResources
        | RendererFeature::BufferResources
        | RendererFeature::TextureResources
        | RendererFeature::SamplerResources
        | RendererFeature::MaterialSystem
        | RendererFeature::RetainedScene
        | RendererFeature::CameraViewRenderTargets
        | RendererFeature::EcsExtractBoundary => RendererFeatureImplementation::FacadeSemantic,
        RendererFeature::ShaderReflection | RendererFeature::PipelineStatistics => {
            RendererFeatureImplementation::FacadeSemantic
        }
        RendererFeature::MultiDrawIndirect
        | RendererFeature::BindlessTextures
        | RendererFeature::AsyncCompute
        | RendererFeature::RayTracing
        | RendererFeature::MeshShader
        | RendererFeature::VariableRateShading
        | RendererFeature::GpuDrivenRendering
        | RendererFeature::OcclusionCulling
        | RendererFeature::VirtualTexturing
        | RendererFeature::MotionVectors
        | RendererFeature::Lights
        | RendererFeature::ShadowMapping
        | RendererFeature::EnvironmentIbl
        | RendererFeature::RenderGraph
        | RendererFeature::CustomRenderGraphPasses
        | RendererFeature::Standard3dPipeline => RendererFeatureImplementation::GraphSemantic,
        RendererFeature::BackendGpuDeformation
        | RendererFeature::BackendIblConvolution
        | RendererFeature::BackendRealStandard3dPipeline
        | RendererFeature::NonblockingResourceRetirementPoll
        | RendererFeature::CompleteBackendPipelineCache => {
            RendererFeatureImplementation::ConfigGate
        }
        RendererFeature::BackendVulkan
        | RendererFeature::BackendMetal
        | RendererFeature::BackendD3d12
        | RendererFeature::NativeFrameDebuggerCapture => {
            RendererFeatureImplementation::ReservedUnsupported
        }
    }
}

fn renderer_feature_unsupported_reason(feature: RendererFeature) -> Option<&'static str> {
    match feature {
        RendererFeature::BackendVulkan => Some("reserved until a Vulkan backend is implemented"),
        RendererFeature::BackendMetal => Some("reserved until a Metal backend is implemented"),
        RendererFeature::BackendD3d12 => Some("reserved until a D3D12 backend is implemented"),
        RendererFeature::BackendWgpu => Some("backend-wgpu Cargo feature is not enabled"),
        RendererFeature::Surface => Some("requires Renderer::with_surface and a surface backend"),
        RendererFeature::TimestampQuery => {
            Some("requires RendererConfig::gpu_profiling and backend timestamp support")
        }
        RendererFeature::PipelineStatistics => {
            Some("requires pipeline-statistics Cargo feature and backend support")
        }
        RendererFeature::VertexAttribute64Bit => {
            Some("requires backend support for 64-bit vertex attributes")
        }
        RendererFeature::BackgroundResourceRetirement => {
            Some("background resource retirement is unavailable for this renderer")
        }
        RendererFeature::NonblockingResourceRetirementPoll => Some(
            "requires backend support for nonblocking submission-index retirement polling; current wgpu backend uses queue-empty fallback",
        ),
        RendererFeature::NativeFrameDebuggerCapture => Some(
            "native RenderDoc/external debugger SDK capture is not linked; use registered external frame capture hooks",
        ),
        RendererFeature::BackendGpuDeformation => Some(
            "backend GPU skinning/morph deformation buffers are not implemented; current deformation output is renderer/RHI observable facade semantics",
        ),
        RendererFeature::BackendIblConvolution => Some(
            "backend-real IBL/environment convolution is not implemented; current environment bake is renderer-retained facade output",
        ),
        RendererFeature::BackendRealStandard3dPipeline => Some(
            "full backend-real standard 3D pipeline execution is not complete; current standard graph mixes facade, RHI, and partial backend-wgpu execution",
        ),
        RendererFeature::CompleteBackendPipelineCache => Some(
            "complete backend-native pipeline cache coverage is not implemented; current reflected backend-wgpu cache is partial and facade cache entries can still lack backend objects",
        ),
        RendererFeature::MultiDrawIndirect => Some("requires multi-draw-indirect Cargo feature"),
        RendererFeature::BindlessTextures => Some("requires bindless Cargo feature"),
        RendererFeature::AsyncCompute => Some("requires async-compute Cargo feature"),
        RendererFeature::RayTracing => Some("requires ray-tracing Cargo feature"),
        RendererFeature::MeshShader => Some("requires mesh-shader Cargo feature"),
        RendererFeature::VariableRateShading => Some("requires variable-rate-shading Cargo feature"),
        RendererFeature::GpuDrivenRendering => Some("requires gpu-driven Cargo feature"),
        RendererFeature::VirtualTexturing => Some("requires virtual-texturing Cargo feature"),
        RendererFeature::Compute
        | RendererFeature::IndirectDraw
        | RendererFeature::StorageTextures
        | RendererFeature::OcclusionCulling
        | RendererFeature::ShaderReflection
        | RendererFeature::FrameCapture
        | RendererFeature::ExternalFrameCaptureHooks
        | RendererFeature::DebugDraw
        | RendererFeature::EditorDebugReports
        | RendererFeature::SkeletalAnimation
        | RendererFeature::MorphTargets
        | RendererFeature::LodSelection
        | RendererFeature::MotionVectors
        | RendererFeature::Lights
        | RendererFeature::ShadowMapping
        | RendererFeature::EnvironmentIbl
        | RendererFeature::RenderGraph
        | RendererFeature::CustomRenderGraphPasses
        | RendererFeature::Standard3dPipeline
        | RendererFeature::PipelineCache
        | RendererFeature::ShaderVariantCache => Some("required renderer graph feature is unavailable"),
        RendererFeature::UploadQueue
        | RendererFeature::ResourceResidency
        | RendererFeature::StreamingResources
        | RendererFeature::DelayedResourceDestroy
        | RendererFeature::ResourceLifecycle
        | RendererFeature::MeshResources
        | RendererFeature::BufferResources
        | RendererFeature::TextureResources
        | RendererFeature::SamplerResources
        | RendererFeature::MaterialSystem
        | RendererFeature::RetainedScene
        | RendererFeature::CameraViewRenderTargets
        | RendererFeature::EcsExtractBoundary => {
            Some("required renderer memory/resource feature is unavailable")
        }
    }
}

