impl FrameStats {
    pub fn post_process_backend_coverage(&self) -> FramePostProcessBackendCoverage {
        post_process_backend_coverage(
            &self.post_process_outputs,
            &self.graph.rhi_executed_pass_labels,
        )
    }

    pub fn public_graph_export_count(&self) -> usize {
        self.public_graph_exported_textures + self.public_graph_exported_buffers
    }

    pub fn public_graph_promoted_export_count(&self) -> usize {
        self.public_graph_promoted_textures + self.public_graph_promoted_buffers
    }

    pub fn public_graph_imported_export_count(&self) -> usize {
        self.public_graph_imported_texture_exports + self.public_graph_imported_buffer_exports
    }

    pub fn public_graph_export_label_count(&self) -> usize {
        self.public_graph_exported_texture_labels.len()
            + self.public_graph_exported_buffer_labels.len()
    }

    pub fn public_graph_promoted_export_label_count(&self) -> usize {
        self.public_graph_promoted_texture_labels.len()
            + self.public_graph_promoted_buffer_labels.len()
    }

    pub fn public_graph_imported_export_label_count(&self) -> usize {
        self.public_graph_imported_texture_export_labels.len()
            + self.public_graph_imported_buffer_export_labels.len()
    }

    pub fn public_graph_texture_region_export_label_count(&self) -> usize {
        self.public_graph_texture_region_export_labels.len()
    }

    pub fn public_graph_resolved_msaa_texture_export_label_count(&self) -> usize {
        self.public_graph_resolved_msaa_texture_export_labels.len()
    }

    pub fn has_complete_public_graph_texture_region_export_label_coverage(&self) -> bool {
        self.public_graph_texture_region_exports
            == self.public_graph_texture_region_export_labels.len()
    }

    pub fn has_complete_public_graph_export_label_coverage(&self) -> bool {
        self.public_graph_exported_textures == self.public_graph_exported_texture_labels.len()
            && self.public_graph_exported_buffers == self.public_graph_exported_buffer_labels.len()
            && self.public_graph_promoted_textures
                == self.public_graph_promoted_texture_labels.len()
            && self.public_graph_promoted_buffers == self.public_graph_promoted_buffer_labels.len()
            && self.public_graph_imported_texture_exports
                == self.public_graph_imported_texture_export_labels.len()
            && self.public_graph_imported_buffer_exports
                == self.public_graph_imported_buffer_export_labels.len()
            && self.public_graph_resolved_msaa_texture_exports
                == self.public_graph_resolved_msaa_texture_export_labels.len()
            && self.has_complete_public_graph_texture_region_export_label_coverage()
    }

    pub fn public_frame_outputs_with_packed_subresources(&self) -> usize {
        self.public_frame_outputs
            .iter()
            .filter(|output| output.has_packed_subresources())
            .count()
    }

    pub fn public_frame_output_subresource_bytes(&self) -> u64 {
        self.public_frame_outputs
            .iter()
            .map(FramePublicFrameOutput::subresource_byte_len)
            .sum()
    }

    pub fn all_public_frame_outputs_have_complete_subresource_layouts(&self) -> bool {
        self.public_frame_outputs
            .iter()
            .all(FramePublicFrameOutput::has_complete_view_subresource_layout)
    }

    pub fn unsupported_public_frame_output_count(&self) -> usize {
        self.unsupported_public_frame_outputs.len()
    }
}

