#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum RendererGraphCapability {
    PublicBufferImportExport,
    PublicTextureD2BaseMipImportExport,
    PublicTexturePackedMipImportExport,
    PublicTextureFlattenedLayerImportExport,
    GraphCreatedD2TransientPromotion,
    GraphCreatedMsaaResolvePromotion,
    CustomMsaaResolvePassContext,
    PersistentBackendImportCache,
    ReadbackBackedSurfaceGraphExport,
    DirectSwapchainGraphExport,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum RendererGraphCapabilityLevel {
    Implemented,
    CompatibilityPath,
    BackendImplemented,
    CapabilityGated,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RendererGraphCapabilitySupport {
    pub capability: RendererGraphCapability,
    pub supported: bool,
    pub level: RendererGraphCapabilityLevel,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, Default, PartialEq, Eq)]
pub struct RendererRenderGraphSupport {
    pub capabilities: Vec<RendererGraphCapabilitySupport>,
}

impl RendererRenderGraphSupport {
    pub fn support_for(
        &self,
        capability: RendererGraphCapability,
    ) -> Option<&RendererGraphCapabilitySupport> {
        self.capabilities
            .iter()
            .find(|support| support.capability == capability)
    }

    pub fn unsupported_capabilities(&self) -> Vec<RendererGraphCapability> {
        self.capabilities
            .iter()
            .filter(|support| !support.supported)
            .map(|support| support.capability)
            .collect()
    }

    pub fn all_supported(&self) -> bool {
        self.capabilities.iter().all(|support| support.supported)
    }
}

fn graph_capability(
    capability: RendererGraphCapability,
    supported: bool,
    level: RendererGraphCapabilityLevel,
    limitation: Option<&'static str>,
) -> RendererGraphCapabilitySupport {
    RendererGraphCapabilitySupport {
        capability,
        supported,
        level,
        limitation,
    }
}

