#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RendererGraphTextureRegionExportUnsupported {
    pub texture: TextureHandle,
    pub label: Option<String>,
    pub reason: String,
}

impl RendererGraphImportSupport {
    pub fn unsupported_texture_imports(&self) -> usize {
        self.textures
            .iter()
            .filter(|support| !support.supported)
            .count()
    }

    pub fn unsupported_buffer_imports(&self) -> usize {
        self.buffers
            .iter()
            .filter(|support| !support.supported)
            .count()
    }

    pub fn unsupported_imports(&self) -> usize {
        self.unsupported_texture_imports() + self.unsupported_buffer_imports()
    }

    pub fn all_imports_supported(&self) -> bool {
        self.unsupported_imports() == 0
    }

    pub fn texture_imports_with_incomplete_subresource_coverage(&self) -> usize {
        self.textures
            .iter()
            .filter(|support| !support.complete_subresource_coverage)
            .count()
    }

    pub fn texture_imports_with_packed_subresources(&self) -> usize {
        self.textures
            .iter()
            .filter(|support| support.has_packed_subresources())
            .count()
    }

    pub fn resolved_msaa_texture_imports(&self) -> usize {
        self.textures
            .iter()
            .filter(|support| support.resolved_msaa_compatible)
            .count()
    }

    pub fn texture_import_subresource_bytes(&self) -> u64 {
        self.textures
            .iter()
            .map(RendererGraphTextureImportSupport::subresource_byte_len)
            .sum()
    }

    pub fn buffer_imports_with_incomplete_byte_coverage(&self) -> usize {
        self.buffers
            .iter()
            .filter(|support| !support.complete_byte_coverage)
            .count()
    }

    pub fn buffer_imports_with_disjoint_byte_ranges(&self) -> usize {
        self.buffers
            .iter()
            .filter(|support| support.has_disjoint_byte_ranges())
            .count()
    }

    pub fn buffer_import_represented_bytes(&self) -> u64 {
        self.buffers
            .iter()
            .map(RendererGraphBufferImportSupport::represented_byte_len)
            .sum()
    }

    pub fn all_texture_imports_complete_subresource_coverage(&self) -> bool {
        self.textures
            .iter()
            .all(|support| support.complete_subresource_coverage)
    }

    pub fn all_buffer_imports_complete_byte_coverage(&self) -> bool {
        self.buffers
            .iter()
            .all(|support| support.complete_byte_coverage)
    }

    pub fn has_incomplete_import_coverage(&self) -> bool {
        self.texture_imports_with_incomplete_subresource_coverage() != 0
            || self.buffer_imports_with_incomplete_byte_coverage() != 0
    }

    pub fn texture_region_exports(&self) -> usize {
        self.texture_region_exports.len()
    }

    pub fn supported_texture_region_exports(&self) -> usize {
        self.texture_region_exports
            .iter()
            .filter(|support| support.supported)
            .count()
    }

    pub fn unsupported_texture_region_exports(&self) -> usize {
        self.texture_region_exports
            .iter()
            .filter(|support| !support.supported)
            .count()
    }

    pub fn has_texture_region_exports(&self) -> bool {
        !self.texture_region_exports.is_empty()
    }

    pub fn has_unsupported_texture_region_exports(&self) -> bool {
        self.unsupported_texture_region_exports() != 0
    }

    pub fn all_texture_region_exports_supported(&self) -> bool {
        self.texture_region_exports
            .iter()
            .all(|support| support.supported)
    }

    pub fn texture_region_export_subresource_bytes(&self) -> u64 {
        self.texture_region_exports
            .iter()
            .map(RendererGraphTextureRegionExportSupport::subresource_byte_len)
            .sum()
    }

    pub fn resolved_msaa_texture_region_exports(&self) -> usize {
        self.texture_region_exports
            .iter()
            .filter(|support| support.resolved_msaa_compatible)
            .count()
    }

    pub fn texture_region_export_labels(&self) -> Vec<String> {
        let mut labels = self
            .texture_region_exports
            .iter()
            .filter_map(|support| support.label.clone())
            .collect::<Vec<_>>();
        labels.sort();
        labels
    }

    pub fn supported_texture_region_export_labels(&self) -> Vec<String> {
        let mut labels = self
            .texture_region_exports
            .iter()
            .filter(|support| support.supported)
            .filter_map(|support| support.label.clone())
            .collect::<Vec<_>>();
        labels.sort();
        labels
    }

    pub fn unsupported_texture_region_export_labels(&self) -> Vec<String> {
        let mut labels = self
            .texture_region_exports
            .iter()
            .filter(|support| !support.supported)
            .filter_map(|support| support.label.clone())
            .collect::<Vec<_>>();
        labels.sort();
        labels
    }

    pub fn unsupported_texture_region_export_reasons(&self) -> Vec<String> {
        let mut reasons = self
            .texture_region_exports
            .iter()
            .filter_map(|support| support.unsupported_reason.clone())
            .collect::<Vec<_>>();
        reasons.sort();
        reasons
    }

    pub fn unsupported_texture_region_export_reason_count(&self) -> usize {
        self.unsupported_texture_region_exports_with_reasons().len()
    }

    pub fn has_unsupported_texture_region_export_reasons(&self) -> bool {
        self.unsupported_texture_region_export_reason_count() != 0
    }

    pub fn unsupported_texture_region_exports_with_reasons(
        &self,
    ) -> Vec<RendererGraphTextureRegionExportUnsupported> {
        let mut unsupported = self
            .texture_region_exports
            .iter()
            .filter_map(|support| {
                support.unsupported_reason.as_ref().map(|reason| {
                    RendererGraphTextureRegionExportUnsupported {
                        texture: support.texture,
                        label: support.label.clone(),
                        reason: reason.clone(),
                    }
                })
            })
            .collect::<Vec<_>>();
        unsupported.sort_by(|left, right| left.label.cmp(&right.label));
        unsupported
    }

    pub fn has_complete_texture_region_export_label_coverage(&self) -> bool {
        self.texture_region_exports.len() == self.texture_region_export_labels().len()
    }
}

