#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum DeformationFeature {
    SkeletalAnimation,
    MorphTargets,
    LodSelection,
    MotionVectors,
    BackendGpuDeformation,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum DeformationImplementationLevel {
    FacadeSemantic,
    GraphObservable,
    BackendGpu,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DeformationFeatureSupport {
    pub feature: DeformationFeature,
    pub supported: bool,
    pub implementation: DeformationImplementationLevel,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DeformationSupport {
    pub features: Vec<DeformationFeatureSupport>,
}

impl DeformationSupport {
    pub fn current(backend_gpu_supported: bool) -> Self {
        let backend_limitation = (!backend_gpu_supported).then_some(
            "backend GPU skinning/morph deformation buffers and submission path are not implemented; current deformation is facade/graph observable",
        );
        Self {
            features: vec![
                DeformationFeatureSupport {
                    feature: DeformationFeature::SkeletalAnimation,
                    supported: true,
                    implementation: DeformationImplementationLevel::FacadeSemantic,
                    limitation: Some(
                        "skeletal animation is retained and frame-observable; backend GPU skinning is reported separately",
                    ),
                },
                DeformationFeatureSupport {
                    feature: DeformationFeature::MorphTargets,
                    supported: true,
                    implementation: DeformationImplementationLevel::FacadeSemantic,
                    limitation: Some(
                        "morph target weights are retained and frame-observable; backend GPU morph blending is reported separately",
                    ),
                },
                DeformationFeatureSupport {
                    feature: DeformationFeature::LodSelection,
                    supported: true,
                    implementation: DeformationImplementationLevel::GraphObservable,
                    limitation: Some(
                        "LOD selection is renderer/graph observable; backend meshlet-driven LOD remains separate",
                    ),
                },
                DeformationFeatureSupport {
                    feature: DeformationFeature::MotionVectors,
                    supported: true,
                    implementation: DeformationImplementationLevel::GraphObservable,
                    limitation: Some(
                        "motion vector resource accounting is frame-observable; full velocity-buffer generation is separate",
                    ),
                },
                DeformationFeatureSupport {
                    feature: DeformationFeature::BackendGpuDeformation,
                    supported: backend_gpu_supported,
                    implementation: if backend_gpu_supported {
                        DeformationImplementationLevel::BackendGpu
                    } else {
                        DeformationImplementationLevel::GraphObservable
                    },
                    limitation: backend_limitation,
                },
            ],
        }
    }

    pub fn support_for(&self, feature: DeformationFeature) -> Option<&DeformationFeatureSupport> {
        self.features
            .iter()
            .find(|support| support.feature == feature)
    }

    pub fn unsupported_features(&self) -> Vec<DeformationFeature> {
        self.features
            .iter()
            .filter(|support| !support.supported)
            .map(|support| support.feature)
            .collect()
    }

    pub fn all_supported(&self) -> bool {
        self.features.iter().all(|support| support.supported)
    }

    pub fn backend_gpu_supported(&self) -> bool {
        self.support_for(DeformationFeature::BackendGpuDeformation)
            .is_some_and(|support| support.supported)
    }
}

impl Default for DeformationSupport {
    fn default() -> Self {
        Self::current(false)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum RendererLightingFeature {
    RetainedLights,
    ShadowMapping,
    EnvironmentIbl,
    BackendIblConvolution,
    EnvironmentCapture,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum RendererLightingImplementationLevel {
    FacadeSemantic,
    GraphObservable,
    BackendGenerated,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RendererLightingFeatureSupport {
    pub feature: RendererLightingFeature,
    pub supported: bool,
    pub implementation: RendererLightingImplementationLevel,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RendererLightingSupport {
    pub features: Vec<RendererLightingFeatureSupport>,
}

impl RendererLightingSupport {
    pub fn current(backend_ibl_convolution_supported: bool) -> Self {
        let backend_limitation = (!backend_ibl_convolution_supported).then_some(
            "backend-real environment convolution/capture is not implemented; current environment bake is retained facade output",
        );
        Self {
            features: vec![
                RendererLightingFeatureSupport {
                    feature: RendererLightingFeature::RetainedLights,
                    supported: true,
                    implementation: RendererLightingImplementationLevel::FacadeSemantic,
                    limitation: Some(
                        "directional, point, spot, area, and custom lights are retained and frame-observable; full physically based clustered lighting remains separate",
                    ),
                },
                RendererLightingFeatureSupport {
                    feature: RendererLightingFeature::ShadowMapping,
                    supported: true,
                    implementation: RendererLightingImplementationLevel::GraphObservable,
                    limitation: Some(
                        "shadow outputs and backend pass observability exist; complete production shadow filtering/caching remains separate",
                    ),
                },
                RendererLightingFeatureSupport {
                    feature: RendererLightingFeature::EnvironmentIbl,
                    supported: true,
                    implementation: RendererLightingImplementationLevel::FacadeSemantic,
                    limitation: Some(
                        "environment/IBL descriptors and bake outputs are retained and observable; backend convolution is reported separately",
                    ),
                },
                RendererLightingFeatureSupport {
                    feature: RendererLightingFeature::BackendIblConvolution,
                    supported: backend_ibl_convolution_supported,
                    implementation: if backend_ibl_convolution_supported {
                        RendererLightingImplementationLevel::BackendGenerated
                    } else {
                        RendererLightingImplementationLevel::GraphObservable
                    },
                    limitation: backend_limitation,
                },
                RendererLightingFeatureSupport {
                    feature: RendererLightingFeature::EnvironmentCapture,
                    supported: false,
                    implementation: RendererLightingImplementationLevel::GraphObservable,
                    limitation: Some(
                        "runtime backend cubemap capture/probe rendering is not implemented; current environment data is descriptor/bake based",
                    ),
                },
            ],
        }
    }

    pub fn support_for(
        &self,
        feature: RendererLightingFeature,
    ) -> Option<&RendererLightingFeatureSupport> {
        self.features
            .iter()
            .find(|support| support.feature == feature)
    }

    pub fn unsupported_features(&self) -> Vec<RendererLightingFeature> {
        self.features
            .iter()
            .filter(|support| !support.supported)
            .map(|support| support.feature)
            .collect()
    }

    pub fn all_supported(&self) -> bool {
        self.features.iter().all(|support| support.supported)
    }

    pub fn backend_ibl_convolution_supported(&self) -> bool {
        self.support_for(RendererLightingFeature::BackendIblConvolution)
            .is_some_and(|support| support.supported)
    }
}

impl Default for RendererLightingSupport {
    fn default() -> Self {
        Self::current(false)
    }
}

