#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum PostProcessEffect {
    Hdr,
    Bloom,
    Taa,
    Fxaa,
    Ssao,
    Ssr,
    DepthOfField,
    MotionBlur,
    Tonemap,
    ColorGrading,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum PostProcessImplementationLevel {
    FacadeOnly,
    BackendSampledMinimal,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct PostProcessEffectSupport {
    pub effect: PostProcessEffect,
    pub backend_visible: bool,
    pub production_ready: bool,
    pub implementation: PostProcessImplementationLevel,
    pub backend_label_token: Option<&'static str>,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct PostProcessSupport {
    pub effects: Vec<PostProcessEffectSupport>,
}

impl PostProcessSupport {
    pub fn facade_only() -> Self {
        Self::new(false)
    }

    pub fn backend_wgpu_sampled() -> Self {
        Self::new(true)
    }

    fn new(backend_visible: bool) -> Self {
        Self {
            effects: vec![
                post_process_effect_support(
                    PostProcessEffect::Hdr,
                    "Hdr",
                    backend_visible,
                    "HDR is backend-visible as a sampled exposure branch; HDR swapchain negotiation, white point, and display policy remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::Bloom,
                    "Bloom",
                    backend_visible,
                    "bloom is backend-visible as a single-pass bright-neighbor contribution; multi-resolution threshold/downsample/blur/upsample resources remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::Taa,
                    "Taa",
                    backend_visible,
                    "TAA is backend-visible as a sampled resolve branch; history, jitter, reprojection, and neighborhood rejection remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::Fxaa,
                    "Fxaa",
                    backend_visible,
                    "FXAA is backend-visible as a sampled filter branch; quality presets and full edge-search tuning remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::Ssao,
                    "Ssao",
                    backend_visible,
                    "SSAO is backend-visible as a sampled local-contrast branch; depth/normal kernel sampling and temporal filtering remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::Ssr,
                    "Ssr",
                    backend_visible,
                    "SSR is backend-visible as a sampled reflection-tint branch; depth/normal ray marching and resolve resources remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::DepthOfField,
                    "Depth Of Field",
                    backend_visible,
                    "depth of field is backend-visible as a sampled radial blur branch; circle-of-confusion and blur-chain resources remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::MotionBlur,
                    "Motion Blur",
                    backend_visible,
                    "motion blur is backend-visible as a sampled branch; velocity-buffer blur and tile/max velocity resources remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::Tonemap,
                    "Tonemap",
                    backend_visible,
                    "tonemap is backend-visible in the sampled post-process pass; filmic/display-mapping controls remain production gaps",
                ),
                post_process_effect_support(
                    PostProcessEffect::ColorGrading,
                    "Color Grading",
                    backend_visible,
                    "color grading is backend-visible as a sampled curve; user-provided LUT texture lifecycle and LUT sampling remain production gaps",
                ),
            ],
        }
    }

    pub fn support_for(&self, effect: PostProcessEffect) -> Option<&PostProcessEffectSupport> {
        self.effects.iter().find(|support| support.effect == effect)
    }

    pub fn backend_visible_effects(&self) -> Vec<PostProcessEffect> {
        self.effects
            .iter()
            .filter(|support| support.backend_visible)
            .map(|support| support.effect)
            .collect()
    }

    pub fn production_gap_effects(&self) -> Vec<PostProcessEffect> {
        self.effects
            .iter()
            .filter(|support| !support.production_ready)
            .map(|support| support.effect)
            .collect()
    }

    pub fn all_backend_visible(&self) -> bool {
        self.effects.iter().all(|support| support.backend_visible)
    }

    pub fn all_production_ready(&self) -> bool {
        self.effects.iter().all(|support| support.production_ready)
    }
}

impl Default for PostProcessSupport {
    fn default() -> Self {
        Self::facade_only()
    }
}

fn post_process_effect_support(
    effect: PostProcessEffect,
    backend_label_token: &'static str,
    backend_visible: bool,
    limitation: &'static str,
) -> PostProcessEffectSupport {
    PostProcessEffectSupport {
        effect,
        backend_visible,
        production_ready: false,
        implementation: if backend_visible {
            PostProcessImplementationLevel::BackendSampledMinimal
        } else {
            PostProcessImplementationLevel::FacadeOnly
        },
        backend_label_token: backend_visible.then_some(backend_label_token),
        limitation: Some(limitation),
    }
}

