#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash)]
pub enum FrameCaptureBackend {
    #[default]
    Internal,
    RenderDoc,
    ExternalDebugger,
}

impl FrameCaptureBackend {
    pub const ALL: [Self; 3] = [Self::Internal, Self::RenderDoc, Self::ExternalDebugger];

    pub fn all() -> &'static [Self] {
        &Self::ALL
    }

    pub fn requires_external_hook(self) -> bool {
        !matches!(self, Self::Internal)
    }

    pub fn sdk_name(self) -> Option<&'static str> {
        match self {
            Self::Internal => None,
            Self::RenderDoc => Some("RenderDoc"),
            Self::ExternalDebugger => Some("external debugger"),
        }
    }

    pub fn unavailable_reason(self) -> Option<&'static str> {
        match self {
            Self::Internal => None,
            Self::RenderDoc => Some(
                "RenderDoc SDK integration is not linked; register a RenderDoc capture hook before requesting this backend",
            ),
            Self::ExternalDebugger => Some(
                "external debugger integration is not linked; register an external capture hook before requesting this backend",
            ),
        }
    }
}

