#[derive(Clone, Debug, PartialEq, Eq)]
pub struct FrameCaptureSupport {
    pub backends: Vec<FrameCaptureBackendInfo>,
    pub internal_capture_supported: bool,
    pub external_hook_backends: Vec<FrameCaptureBackend>,
    pub native_sdk_blocked_backends: Vec<FrameCaptureBackend>,
    pub unavailable_backends: Vec<FrameCaptureBackend>,
    pub complete_native_sdk_integration: bool,
}

impl FrameCaptureSupport {
    fn from_backend_infos(
        backends: Vec<FrameCaptureBackendInfo>,
        callback_registered: &[FrameCaptureBackend],
    ) -> Self {
        let internal_capture_supported = backends.iter().any(|info| {
            info.backend == FrameCaptureBackend::Internal
                && info.available
                && info.integration == FrameCaptureIntegration::Internal
        });
        let external_hook_backends = backends
            .iter()
            .filter(|info| info.integration == FrameCaptureIntegration::ExternalHookRegistered)
            .map(|info| info.backend)
            .collect::<Vec<_>>();
        let native_sdk_blocked_backends = backends
            .iter()
            .filter(|info| {
                info.requires_external_hook
                    && info.integration == FrameCaptureIntegration::ExternalSdkRequired
            })
            .map(|info| info.backend)
            .collect::<Vec<_>>();
        let unavailable_backends = backends
            .iter()
            .filter(|info| !info.available)
            .map(|info| info.backend)
            .collect::<Vec<_>>();
        let complete_native_sdk_integration = backends.iter().all(|info| {
            !info.requires_external_hook
                || (info.integration == FrameCaptureIntegration::ExternalHookRegistered
                    && callback_registered.contains(&info.backend))
        });
        Self {
            backends,
            internal_capture_supported,
            external_hook_backends,
            native_sdk_blocked_backends,
            unavailable_backends,
            complete_native_sdk_integration,
        }
    }

    pub fn backend_info(&self, backend: FrameCaptureBackend) -> Option<&FrameCaptureBackendInfo> {
        self.backends.iter().find(|info| info.backend == backend)
    }

    pub fn backend_available(&self, backend: FrameCaptureBackend) -> bool {
        self.backend_info(backend)
            .is_some_and(|info| info.available)
    }
}

impl Default for FrameCaptureSupport {
    fn default() -> Self {
        let backends = FrameCaptureBackend::all()
            .iter()
            .copied()
            .map(|backend| {
                let requires_external_hook = backend.requires_external_hook();
                let available = !requires_external_hook;
                FrameCaptureBackendInfo {
                    backend,
                    available,
                    requires_external_hook,
                    integration: if requires_external_hook {
                        FrameCaptureIntegration::ExternalSdkRequired
                    } else {
                        FrameCaptureIntegration::Internal
                    },
                    sdk_name: backend.sdk_name(),
                    registered_hook_label: None,
                    registered_sdk_name: None,
                    unavailable_reason: if available {
                        None
                    } else {
                        backend.unavailable_reason()
                    },
                    status: if available {
                        FrameCaptureStatus::Captured
                    } else {
                        FrameCaptureStatus::BackendUnavailable
                    },
                }
            })
            .collect();
        Self::from_backend_infos(backends, &[])
    }
}

