#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum DebugToolingFeature {
    DebugDrawCommands,
    PickingReadback,
    FrameDebugReport,
    FrameCapture,
    NativeFrameDebuggerCapture,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum DebugToolingImplementationLevel {
    FacadeSemantic,
    FrameObservable,
    ExternalSdkRequired,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DebugToolingFeatureSupport {
    pub feature: DebugToolingFeature,
    pub supported: bool,
    pub implementation: DebugToolingImplementationLevel,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DebugToolingSupport {
    pub features: Vec<DebugToolingFeatureSupport>,
}

impl DebugToolingSupport {
    pub fn current(native_frame_debugger_supported: bool) -> Self {
        Self {
            features: vec![
                DebugToolingFeatureSupport {
                    feature: DebugToolingFeature::DebugDrawCommands,
                    supported: true,
                    implementation: DebugToolingImplementationLevel::FacadeSemantic,
                    limitation: Some(
                        "debug draw and editor gizmo visualization commands are retained and frame-observable; live editor interaction/event routing remains outside this renderer API",
                    ),
                },
                DebugToolingFeatureSupport {
                    feature: DebugToolingFeature::PickingReadback,
                    supported: true,
                    implementation: DebugToolingImplementationLevel::FrameObservable,
                    limitation: Some(
                        "picking produces renderer-visible tickets/results; backend-specific editor selection tooling is separate",
                    ),
                },
                DebugToolingFeatureSupport {
                    feature: DebugToolingFeature::FrameDebugReport,
                    supported: true,
                    implementation: DebugToolingImplementationLevel::FrameObservable,
                    limitation: Some(
                        "frame debug reports expose renderer state snapshots; live editor UI docking/interaction remains outside this crate",
                    ),
                },
                DebugToolingFeatureSupport {
                    feature: DebugToolingFeature::FrameCapture,
                    supported: true,
                    implementation: DebugToolingImplementationLevel::FrameObservable,
                    limitation: Some(
                        "internal capture and registered external-hook handoff are supported; native debugger SDK integration is reported separately",
                    ),
                },
                DebugToolingFeatureSupport {
                    feature: DebugToolingFeature::NativeFrameDebuggerCapture,
                    supported: native_frame_debugger_supported,
                    implementation: DebugToolingImplementationLevel::ExternalSdkRequired,
                    limitation: (!native_frame_debugger_supported).then_some(
                        "native RenderDoc/external debugger SDK capture is not linked; use registered frame capture hooks",
                    ),
                },
            ],
        }
    }

    pub fn support_for(&self, feature: DebugToolingFeature) -> Option<&DebugToolingFeatureSupport> {
        self.features
            .iter()
            .find(|support| support.feature == feature)
    }

    pub fn unsupported_features(&self) -> Vec<DebugToolingFeature> {
        self.features
            .iter()
            .filter(|support| !support.supported)
            .map(|support| support.feature)
            .collect()
    }

    pub fn all_supported(&self) -> bool {
        self.features.iter().all(|support| support.supported)
    }
}

impl Default for DebugToolingSupport {
    fn default() -> Self {
        Self::current(false)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum ResourceLifecycleClass {
    Mesh,
    Buffer,
    Texture,
    Sampler,
    Shader,
    Material,
    MaterialTemplate,
    Scene,
    View,
    RenderTarget,
    Camera,
    Environment,
    RenderGraphExtension,
    SkeletonInstance,
    MorphWeights,
    LodGroup,
    PipelineCacheEntry,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum ResourceBackendResidencyLevel {
    FacadeRetained,
    BackendMirrored,
    BackendPersistentPartial,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ResourceLifecycleClassSupport {
    pub class: ResourceLifecycleClass,
    pub create_update_destroy_supported: bool,
    pub generation_stale_handle_errors_supported: bool,
    pub upload_readback_supported: bool,
    pub residency_supported: bool,
    pub stats_capture_debug_supported: bool,
    pub backend_residency: ResourceBackendResidencyLevel,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ResourceLifecycleSupport {
    pub classes: Vec<ResourceLifecycleClassSupport>,
}

impl ResourceLifecycleSupport {
    pub fn current(backend_wgpu_active: bool) -> Self {
        let backend_level = if backend_wgpu_active {
            ResourceBackendResidencyLevel::BackendPersistentPartial
        } else {
            ResourceBackendResidencyLevel::FacadeRetained
        };
        Self {
            classes: vec![
                lifecycle_support(
                    ResourceLifecycleClass::Mesh,
                    true,
                    true,
                    true,
                    true,
                    true,
                    backend_level,
                    Some(
                        "mesh resources have facade lifecycle/upload/readback/residency observability; complete backend-resident dirty synchronization remains partial",
                    ),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Buffer,
                    true,
                    true,
                    true,
                    true,
                    true,
                    backend_level,
                    Some(
                        "buffer resources have public lifecycle/upload/readback and graph import/export support; persistent backend dirty-range synchronization remains partial",
                    ),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Texture,
                    true,
                    true,
                    true,
                    true,
                    true,
                    backend_level,
                    Some(
                        "texture resources have public lifecycle/upload/readback, graph import/export, and backend material binding invalidation on update/destroy; full native multi-subresource backend synchronization remains partial",
                    ),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Sampler,
                    true,
                    true,
                    false,
                    true,
                    true,
                    backend_level,
                    Some("samplers have lifecycle/residency observability and backend material binding invalidation on destroy but no byte upload/readback payload"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Shader,
                    true,
                    true,
                    false,
                    true,
                    true,
                    backend_level,
                    Some("shader hot reload and cache invalidation are observable; backend-native cache coverage is reported separately"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Material,
                    true,
                    true,
                    false,
                    true,
                    true,
                    backend_level,
                    Some("materials have lifecycle, dependency validation, and backend native-pipeline invalidation on parameter removal/replacement; backend bind-group residency is partial"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::MaterialTemplate,
                    true,
                    true,
                    false,
                    true,
                    true,
                    backend_level,
                    Some("material templates invalidate dependent facade/backend cache entries; complete native pipeline cache coverage is separate"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Scene,
                    true,
                    true,
                    false,
                    false,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("retained scenes are facade resources extracted to backend render scenes when rendering"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::View,
                    true,
                    true,
                    false,
                    false,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("views are frame/facade resources with debug/capture observability"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::RenderTarget,
                    true,
                    true,
                    false,
                    true,
                    true,
                    backend_level,
                    Some("render targets have public lifecycle and output observability; direct swapchain graph export is capability-gated"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Camera,
                    true,
                    true,
                    false,
                    false,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("cameras are retained facade resources with frame/debug observability"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::Environment,
                    true,
                    true,
                    true,
                    true,
                    true,
                    backend_level,
                    Some("environment descriptors and bake outputs are observable; backend IBL convolution/capture is reported separately"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::RenderGraphExtension,
                    true,
                    true,
                    false,
                    false,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("graph extensions are retained facade callbacks with frame graph observability"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::SkeletonInstance,
                    true,
                    true,
                    true,
                    true,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("skeleton instances are retained and observable; backend GPU deformation buffers are reported separately"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::MorphWeights,
                    true,
                    true,
                    true,
                    true,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("morph weights are retained and observable; backend GPU morph blending is reported separately"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::LodGroup,
                    true,
                    true,
                    false,
                    true,
                    true,
                    ResourceBackendResidencyLevel::FacadeRetained,
                    Some("LOD groups are retained and frame-observable; backend meshlet-driven LOD is separate"),
                ),
                lifecycle_support(
                    ResourceLifecycleClass::PipelineCacheEntry,
                    true,
                    true,
                    false,
                    true,
                    true,
                    backend_level,
                    Some("pipeline cache entries are observable; complete backend object coverage is reported by PipelineCacheBackendCoverage"),
                ),
            ],
        }
    }

    pub fn support_for(
        &self,
        class: ResourceLifecycleClass,
    ) -> Option<&ResourceLifecycleClassSupport> {
        self.classes.iter().find(|support| support.class == class)
    }

    pub fn all_classes_have_lifecycle(&self) -> bool {
        self.classes.iter().all(|support| {
            support.create_update_destroy_supported
                && support.generation_stale_handle_errors_supported
                && support.stats_capture_debug_supported
        })
    }

    pub fn backend_persistent_partial_classes(&self) -> Vec<ResourceLifecycleClass> {
        self.classes
            .iter()
            .filter(|support| {
                support.backend_residency == ResourceBackendResidencyLevel::BackendPersistentPartial
            })
            .map(|support| support.class)
            .collect()
    }
}

impl Default for ResourceLifecycleSupport {
    fn default() -> Self {
        Self::current(false)
    }
}

fn lifecycle_support(
    class: ResourceLifecycleClass,
    create_update_destroy_supported: bool,
    generation_stale_handle_errors_supported: bool,
    upload_readback_supported: bool,
    residency_supported: bool,
    stats_capture_debug_supported: bool,
    backend_residency: ResourceBackendResidencyLevel,
    limitation: Option<&'static str>,
) -> ResourceLifecycleClassSupport {
    ResourceLifecycleClassSupport {
        class,
        create_update_destroy_supported,
        generation_stale_handle_errors_supported,
        upload_readback_supported,
        residency_supported,
        stats_capture_debug_supported,
        backend_residency,
        limitation,
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum BackendSynchronizationFeature {
    SubmissionBoundaryRetirement,
    BackendTombstoneRetirement,
    QueueEmptyPollFallback,
    NonblockingSubmissionIndexPoll,
    BackgroundRetirementScheduler,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum BackendSynchronizationImplementationLevel {
    FacadeSemantic,
    BackendQueueFallback,
    BackendNonblocking,
    SchedulerThread,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct BackendSynchronizationFeatureSupport {
    pub feature: BackendSynchronizationFeature,
    pub supported: bool,
    pub implementation: BackendSynchronizationImplementationLevel,
    pub limitation: Option<&'static str>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct BackendSynchronizationSupport {
    pub features: Vec<BackendSynchronizationFeatureSupport>,
    pub background_retirement_active: bool,
}

impl BackendSynchronizationSupport {
    pub fn current(
        backend_tombstone_retirement_supported: bool,
        queue_empty_poll_fallback_supported: bool,
        nonblocking_submission_index_poll_supported: bool,
        background_retirement_active: bool,
    ) -> Self {
        Self {
            features: vec![
                BackendSynchronizationFeatureSupport {
                    feature: BackendSynchronizationFeature::SubmissionBoundaryRetirement,
                    supported: true,
                    implementation: BackendSynchronizationImplementationLevel::FacadeSemantic,
                    limitation: Some(
                        "submission-boundary retirement is renderer bookkeeping; backend completion precision is reported separately",
                    ),
                },
                BackendSynchronizationFeatureSupport {
                    feature: BackendSynchronizationFeature::BackendTombstoneRetirement,
                    supported: backend_tombstone_retirement_supported,
                    implementation: BackendSynchronizationImplementationLevel::BackendQueueFallback,
                    limitation: (!backend_tombstone_retirement_supported).then_some(
                        "backend tombstone retirement requires an active backend-wgpu runtime",
                    ),
                },
                BackendSynchronizationFeatureSupport {
                    feature: BackendSynchronizationFeature::QueueEmptyPollFallback,
                    supported: queue_empty_poll_fallback_supported,
                    implementation: BackendSynchronizationImplementationLevel::BackendQueueFallback,
                    limitation: queue_empty_poll_fallback_supported.then_some(
                        "queue-empty polling is a coarse fallback and does not provide true per-submission nonblocking completion",
                    ),
                },
                BackendSynchronizationFeatureSupport {
                    feature: BackendSynchronizationFeature::NonblockingSubmissionIndexPoll,
                    supported: nonblocking_submission_index_poll_supported,
                    implementation: if nonblocking_submission_index_poll_supported {
                        BackendSynchronizationImplementationLevel::BackendNonblocking
                    } else {
                        BackendSynchronizationImplementationLevel::BackendQueueFallback
                    },
                    limitation: (!nonblocking_submission_index_poll_supported).then_some(
                        "current backend completion observability does not expose a true nonblocking per-submission index query",
                    ),
                },
                BackendSynchronizationFeatureSupport {
                    feature: BackendSynchronizationFeature::BackgroundRetirementScheduler,
                    supported: true,
                    implementation: BackendSynchronizationImplementationLevel::SchedulerThread,
                    limitation: Some(
                        "the scheduler thread requests retirement ticks; renderer/backend objects are still retired on renderer-thread safe points",
                    ),
                },
            ],
            background_retirement_active,
        }
    }

    pub fn support_for(
        &self,
        feature: BackendSynchronizationFeature,
    ) -> Option<&BackendSynchronizationFeatureSupport> {
        self.features
            .iter()
            .find(|support| support.feature == feature)
    }

    pub fn unsupported_features(&self) -> Vec<BackendSynchronizationFeature> {
        self.features
            .iter()
            .filter(|support| !support.supported)
            .map(|support| support.feature)
            .collect()
    }

    pub fn true_nonblocking_poll_supported(&self) -> bool {
        self.support_for(BackendSynchronizationFeature::NonblockingSubmissionIndexPoll)
            .is_some_and(|support| support.supported)
    }
}

impl Default for BackendSynchronizationSupport {
    fn default() -> Self {
        Self::current(false, false, false, false)
    }
}

