struct BackgroundResourceRetirementWorker {
    running: Arc<AtomicBool>,
    tick_requested: Arc<AtomicBool>,
    handle: Option<JoinHandle<()>>,
}

impl BackgroundResourceRetirementWorker {
    fn start() -> Self {
        let running = Arc::new(AtomicBool::new(true));
        let tick_requested = Arc::new(AtomicBool::new(true));
        let thread_running = Arc::clone(&running);
        let thread_tick_requested = Arc::clone(&tick_requested);
        let handle = thread::spawn(move || {
            while thread_running.load(Ordering::Acquire) {
                thread_tick_requested.store(true, Ordering::Release);
                thread::sleep(Duration::from_millis(8));
            }
        });
        Self {
            running,
            tick_requested,
            handle: Some(handle),
        }
    }

    fn tick_requested(&self) -> bool {
        self.tick_requested.load(Ordering::Acquire)
    }

    fn consume_tick_request(&self) -> bool {
        self.tick_requested.swap(false, Ordering::AcqRel)
    }

    fn stop(&mut self) {
        self.running.store(false, Ordering::Release);
        if let Some(handle) = self.handle.take() {
            let _ = handle.join();
        }
    }
}

impl Drop for BackgroundResourceRetirementWorker {
    fn drop(&mut self) {
        self.stop();
    }
}

