    #[cfg(feature = "backend-wgpu")]
    fn apply_gpu_profiler_capability_to_runtime(&mut self, runtime: &mut WgpuRendererRuntime) {
        self.gpu_profiler_enabled = initial_gpu_profiler_enabled(&self.config, &self.caps);
        runtime.set_gpu_profiling_enabled(self.gpu_profiler_enabled);
    }

