    pub fn feature_info(&self, feature: RendererFeature) -> RendererFeatureInfo {
        let supported = self.supports_feature(feature);
        let tier = renderer_feature_tier(feature);
        let reason = if supported {
            None
        } else if matches!(feature, RendererFeature::NonblockingResourceRetirementPoll) {
            self.backend_submission_completion_report()
                .limitation
                .or(renderer_feature_unsupported_reason(feature))
        } else {
            renderer_feature_unsupported_reason(feature)
        };
        RendererFeatureInfo {
            feature,
            supported,
            tier,
            implementation: renderer_feature_implementation(feature),
            reason,
        }
    }

    pub fn feature_infos(&self) -> Vec<RendererFeatureInfo> {
        RendererFeature::all()
            .iter()
            .copied()
            .map(|feature| self.feature_info(feature))
            .collect()
    }

    pub fn feature_audit(&self) -> RendererFeatureAudit {
        RendererFeatureAudit::from_infos(&self.feature_infos())
    }

    pub fn feature_support_matrix(&self) -> RendererFeatureSupportMatrix {
        RendererFeatureSupportMatrix::from_infos(&self.feature_infos())
    }

    pub fn cargo_feature_audit(&self) -> RendererCargoFeatureAudit {
        RendererCargoFeatureAudit::from_infos(renderer_cargo_feature_infos())
    }

