    #[test]
    fn prelude_keeps_graph_and_rhi_types_out_of_game_layer_imports() {
        let source = include_str!("lib.rs");
        let start = source.find("pub mod prelude {").unwrap();
        let end = source[start..].find("\n}\n\n#[derive").unwrap() + start;
        let prelude = &source[start..end];

        let exports_identifier = |ident: &str| {
            prelude
                .split(|ch: char| !(ch.is_ascii_alphanumeric() || ch == '_'))
                .any(|token| token == ident)
        };
        for forbidden in [
            "RhiAccess",
            "RhiDevice",
            "RhiCommandBuffer",
            "RenderGraphBuilder",
            "PassBuilder",
            "PassContext",
            "GraphTexture",
            "GraphBuffer",
            "GraphAccess",
            "RenderPassEncoder",
            "ComputePassEncoder",
            "CompiledRenderGraph",
            "ResourceBarrier",
            "TextureReadUsage",
            "BufferReadUsage",
            "QueueType",
            "DrawItem",
            "ShaderInterfaceDesc",
            "ShaderResourceBinding",
            "BindingClass",
            "BindingType",
            "PushConstantRange",
            "VertexInputRequirement",
        ] {
            assert!(
                !exports_identifier(forbidden),
                "prelude should not export graph/RHI or binding layout detail: {forbidden}"
            );
        }
    }

