    #[test]
    fn buffer_resources_are_retained_and_updatable() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("camera"),
                size: 8,
                usage: BufferUsage::UNIFORM | BufferUsage::COPY_DST | BufferUsage::COPY_SRC,
                initial_data: Some(&[1, 2, 3, 4]),
            })
            .unwrap();

        let info = renderer.buffer_info(buffer).unwrap();
        assert_eq!(info.label.as_deref(), Some("camera"));
        assert_eq!(info.size, 8);
        assert!(info.usage.contains(BufferUsage::UNIFORM));
        assert_eq!(info.status, ResourceStatus::Ready);
        assert_eq!(
            renderer.buffer_bytes(buffer).unwrap(),
            &[1, 2, 3, 4, 0, 0, 0, 0]
        );

        renderer
            .update_buffer(
                buffer,
                BufferUpdate {
                    byte_offset: 4,
                    data: &[9, 10, 11, 12],
                },
            )
            .unwrap();
        assert_eq!(
            renderer.buffer_bytes(buffer).unwrap(),
            &[1, 2, 3, 4, 9, 10, 11, 12]
        );
        assert_eq!(
            renderer.resource_status(buffer),
            Some(ResourceStatus::Ready)
        );
        assert!(renderer.memory_stats().resident_bytes >= 8);
    }

    #[test]
    fn buffer_resources_validate_size_usage_and_update_ranges() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        assert!(matches!(
            renderer.create_buffer(BufferDesc {
                label: None,
                size: 0,
                usage: BufferUsage::UNIFORM,
                initial_data: None,
            }),
            Err(RendererError::Validation(_))
        ));
        assert!(matches!(
            renderer.create_buffer(BufferDesc {
                label: None,
                size: 4,
                usage: BufferUsage::empty(),
                initial_data: None,
            }),
            Err(RendererError::Validation(_))
        ));
        assert!(matches!(
            renderer.create_buffer(BufferDesc {
                label: None,
                size: 2,
                usage: BufferUsage::COPY_DST,
                initial_data: Some(&[1, 2, 3]),
            }),
            Err(RendererError::Validation(_))
        ));

        let buffer = renderer
            .create_buffer(BufferDesc {
                label: None,
                size: 4,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        assert!(matches!(
            renderer.update_buffer(
                buffer,
                BufferUpdate {
                    byte_offset: 0,
                    data: &[],
                },
            ),
            Err(RendererError::Validation(_))
        ));
        assert!(matches!(
            renderer.update_buffer(
                buffer,
                BufferUpdate {
                    byte_offset: 3,
                    data: &[1, 2],
                },
            ),
            Err(RendererError::Validation(_))
        ));
        let storage_only = renderer
            .create_buffer(BufferDesc {
                label: None,
                size: 4,
                usage: BufferUsage::STORAGE,
                initial_data: None,
            })
            .unwrap();
        assert!(matches!(
            renderer.update_buffer(
                storage_only,
                BufferUpdate {
                    byte_offset: 0,
                    data: &[1],
                },
            ),
            Err(RendererError::Validation(_))
        ));
        assert!(matches!(
            renderer.update_buffer(
                make_handle(ResourceKind::Buffer, 99, 1),
                BufferUpdate {
                    byte_offset: 0,
                    data: &[1],
                },
            ),
            Err(RendererError::InvalidHandle {
                kind: ResourceKind::Buffer,
                ..
            })
        ));
    }

    #[test]
    fn buffer_update_rejects_stale_generation_handles() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("buffer"),
                size: 4,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();

        let stale_buffer = make_handle(ResourceKind::Buffer, buffer.index(), buffer.generation() + 1);
        assert_eq!(
            renderer.update_buffer(
                stale_buffer,
                BufferUpdate {
                    byte_offset: 0,
                    data: &[1, 2, 3, 4],
                },
            ),
            Err(RendererError::InvalidHandle {
                kind: ResourceKind::Buffer,
                raw: stale_buffer.raw().get(),
            })
        );
    }

