    #[test]
    fn generate_mips_builds_retained_rgba8_chain() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let mut base = Vec::new();
        for value in [
            10_u8, 20, 50, 60, 30, 40, 70, 80, 90, 100, 130, 140, 110, 120, 150, 160,
        ] {
            base.extend_from_slice(&[value, value, value, 255]);
        }
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("mips"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &base,
                    bytes_per_row: 16,
                    rows_per_image: 4,
                }),
            })
            .unwrap();

        assert!(!renderer.texture_info(texture).unwrap().mips_generated);
        renderer.generate_mips(texture).unwrap();

        let info = renderer.texture_info(texture).unwrap();
        assert_eq!(info.mip_levels, 3);
        assert!(info.mips_generated);
        let bytes = renderer.texture_bytes(texture).unwrap();
        assert_eq!(bytes.len(), 4 * 4 * 4 + 2 * 2 * 4 + 4);
        assert_eq!(
            &bytes[64..80],
            &[25, 25, 25, 255, 65, 65, 65, 255, 105, 105, 105, 255, 145, 145, 145, 255,]
        );
        assert_eq!(&bytes[80..84], &[85, 85, 85, 255]);

        renderer
            .update_texture(
                texture,
                TextureUpdate {
                    subresource: TextureSubresource {
                        mip_level: 0,
                        array_layer: 0,
                    },
                    region: TextureRegion {
                        offset: [0, 0, 0],
                        extent: [4, 4, 1],
                    },
                    bytes_per_row: 16,
                    rows_per_image: 4,
                    data: &base,
                },
            )
            .unwrap();
        assert!(!renderer.texture_info(texture).unwrap().mips_generated);
    }

    #[test]
    fn generate_mips_builds_retained_rgba32f_chain() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let mut base = Vec::new();
        for value in 0..16_u32 {
            base.push([value as f32, value as f32 + 10.0, value as f32 + 20.0, 255.0]);
        }
        let base_bytes: Vec<u8> = base
            .iter()
            .flat_map(|texel| encode_texel_color(TextureFormat::Rgba32Float, *texel))
            .collect();
        let encode = |mip: &[[f32; 4]]| -> Vec<u8> {
            mip.iter()
                .flat_map(|texel| encode_texel_color(TextureFormat::Rgba32Float, *texel))
                .collect()
        };

        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("mips_rgba32f"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba32Float,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &base_bytes,
                    bytes_per_row: 64,
                    rows_per_image: 4,
                }),
            })
            .unwrap();

        assert!(!renderer.texture_info(texture).unwrap().mips_generated);
        renderer.generate_mips(texture).unwrap();

        let info = renderer.texture_info(texture).unwrap();
        assert_eq!(info.mip_levels, 3);
        assert!(info.mips_generated);

        let bytes = renderer.texture_bytes(texture).unwrap();
        assert_eq!(bytes.len(), 336);

        let mip1 = generate_next_rgba32f_mip(&base, 4, 4, 2, 2);
        let mip2 = generate_next_rgba32f_mip(&mip1, 2, 2, 1, 1);
        let mut expected_bytes = encode(&base);
        expected_bytes.extend(encode(&mip1));
        expected_bytes.extend(encode(&mip2));
        assert_eq!(bytes, expected_bytes.as_slice());

        renderer
            .update_texture(
                texture,
                TextureUpdate {
                    subresource: TextureSubresource {
                        mip_level: 0,
                        array_layer: 0,
                    },
                    region: TextureRegion {
                        offset: [0, 0, 0],
                        extent: [4, 4, 1],
                    },
                    bytes_per_row: 64,
                    rows_per_image: 4,
                    data: &base_bytes,
                },
            )
            .unwrap();
        assert!(!renderer.texture_info(texture).unwrap().mips_generated);
    }

    #[test]
    fn generate_mips_builds_retained_rgba32f_volume_chain() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let mut base = Vec::new();
        for value in 0..8_u32 {
            base.extend_from_slice(&[
                value as f32,
                value as f32 + 10.0,
                value as f32 + 20.0,
                255.0,
            ]);
        }
        let base_bytes: Vec<u8> = base
            .chunks_exact(4)
            .flat_map(|texel| {
                encode_texel_color(TextureFormat::Rgba32Float, [texel[0], texel[1], texel[2], texel[3]])
            })
            .collect();
        let encode = |mip: &[f32]| -> Vec<u8> {
            mip.chunks_exact(4)
                .flat_map(|texel| {
                    encode_texel_color(
                        TextureFormat::Rgba32Float,
                        [texel[0], texel[1], texel[2], texel[3]],
                    )
                })
                .collect()
        };

        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("mips_rgba32f_volume"),
                dimension: TextureDimension::D3,
                width: 2,
                height: 2,
                depth_or_layers: 2,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba32Float,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &base_bytes,
                    bytes_per_row: 32,
                    rows_per_image: 2,
                }),
            })
            .unwrap();

        assert!(!renderer.texture_info(texture).unwrap().mips_generated);
        renderer.generate_mips(texture).unwrap();

        let info = renderer.texture_info(texture).unwrap();
        assert_eq!(info.mip_levels, 2);
        assert!(info.mips_generated);

        let bytes = renderer.texture_bytes(texture).unwrap();
        assert_eq!(bytes.len(), 144);

        let mip1 = generate_next_rgba32f_volume_mip(&base, [2, 2, 2], [1, 1, 1]);
        let mut expected_bytes = base_bytes.clone();
        expected_bytes.extend(encode(&mip1));
        assert_eq!(bytes, expected_bytes.as_slice());

        renderer
            .update_texture(
                texture,
                TextureUpdate {
                    subresource: TextureSubresource {
                        mip_level: 0,
                        array_layer: 0,
                    },
                    region: TextureRegion {
                        offset: [0, 0, 0],
                        extent: [2, 2, 2],
                    },
                    bytes_per_row: 32,
                    rows_per_image: 2,
                    data: &base_bytes,
                },
            )
            .unwrap();
        assert!(!renderer.texture_info(texture).unwrap().mips_generated);
    }

    #[test]
    fn generate_mips_builds_layered_rgba8_chain() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let mut base = Vec::new();
        for face in 0..6_u8 {
            let value = 10 + face * 20;
            for _ in 0..4 {
                base.extend_from_slice(&[value, value, value, 255]);
            }
        }
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("cube_mips"),
                dimension: TextureDimension::Cube,
                width: 2,
                height: 2,
                depth_or_layers: 6,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_SRC,
                initial_data: Some(TextureInitialData {
                    bytes: &base,
                    bytes_per_row: 8,
                    rows_per_image: 2,
                }),
            })
            .unwrap();

        renderer.generate_mips(texture).unwrap();

        let info = renderer.texture_info(texture).unwrap();
        assert_eq!(info.mip_levels, 2);
        assert!(info.mips_generated);
        let bytes = renderer.texture_bytes(texture).unwrap();
        assert_eq!(bytes.len(), 6 * 2 * 2 * 4 + 6 * 4);
        assert_eq!(&bytes[96..100], &[10, 10, 10, 255]);
        assert_eq!(&bytes[116..120], &[110, 110, 110, 255]);
    }

