    #[test]
    fn pipeline_cache_stats_merge_preserves_facade_counts_and_backend_inventory() {
        let merged = merge_pipeline_cache_backend_objects(
            PipelineCacheStats {
                total: 2,
                ready: 2,
                compiling: 0,
                failed: 0,
                backend_objects: 0,
                shader_interface_layouts: 2,
                entries_used_this_frame: 1,
                ready_unused_entries: 1,
                ready_entries_without_backend_object: 2,
                used_entries_without_backend_object: 1,
                cache_hits_this_frame: 3,
                cache_misses_this_frame: 1,
                invalidated_this_frame: 1,
            },
            &PipelineCacheStats {
                backend_objects: 24,
                ..PipelineCacheStats::default()
            },
        );

        assert_eq!(
            merged,
            PipelineCacheStats {
                total: 2,
                ready: 2,
                compiling: 0,
                failed: 0,
                backend_objects: 24,
                shader_interface_layouts: 2,
                entries_used_this_frame: 1,
                ready_unused_entries: 1,
                ready_entries_without_backend_object: 2,
                used_entries_without_backend_object: 1,
                cache_hits_this_frame: 3,
                cache_misses_this_frame: 1,
                invalidated_this_frame: 1,
            }
        );
        assert_eq!(merged.ready_backend_object_gap(), 2);
        assert_eq!(merged.used_backend_object_gap(), 1);
        assert!(!merged.all_ready_entries_have_backend_objects());
        assert!(!merged.all_used_entries_have_backend_objects());
        assert!(!merged.has_complete_facade_backend_object_coverage());

        let complete = merge_pipeline_cache_backend_objects(
            PipelineCacheStats {
                total: 2,
                ready: 2,
                backend_objects: 0,
                ..PipelineCacheStats::default()
            },
            &PipelineCacheStats {
                backend_objects: 2,
                ..PipelineCacheStats::default()
            },
        );
        assert_eq!(complete.backend_objects, 2);
        assert!(complete.has_complete_facade_backend_object_coverage());
    }

