    #[test]
    fn post_process_support_distinguishes_backend_visible_from_production_ready() {
        let facade = PostProcessSupport::facade_only();
        assert!(!facade.all_backend_visible());
        assert!(!facade.all_production_ready());
        assert_eq!(
            facade.backend_visible_effects(),
            Vec::<PostProcessEffect>::new()
        );
        assert_eq!(facade.production_gap_effects().len(), facade.effects.len());
        assert_eq!(
            facade
                .support_for(PostProcessEffect::Bloom)
                .map(|support| support.implementation),
            Some(PostProcessImplementationLevel::FacadeOnly)
        );

        let backend = PostProcessSupport::backend_wgpu_sampled();
        assert!(backend.all_backend_visible());
        assert!(!backend.all_production_ready());
        assert_eq!(
            backend.backend_visible_effects().len(),
            backend.effects.len()
        );
        assert!(backend
            .production_gap_effects()
            .contains(&PostProcessEffect::ColorGrading));
        assert_eq!(
            backend
                .support_for(PostProcessEffect::DepthOfField)
                .map(|support| support.backend_label_token),
            Some(Some("Depth Of Field"))
        );

        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let renderer_support = renderer.post_process_support();
        assert_eq!(renderer_support, facade);
        assert!(!renderer_support.all_backend_visible());
        let mut stats = FrameStats::default();
        renderer.apply_frame_instrumentation(&mut stats);
        assert_eq!(stats.post_process_support, renderer_support);
        let report = FrameDebugReport::from_stats(&stats);
        assert_eq!(report.post_process_support, renderer_support);
        renderer
            .capture_next_frame(CaptureOptions {
                label: Some("post_process_support".to_owned()),
                backend: FrameCaptureBackend::Internal,
                include_resource_dump: true,
                open_after_capture: false,
            })
            .unwrap();
        renderer.apply_frame_instrumentation(&mut stats);
        let capture = stats.capture.as_ref().expect("capture is attached");
        assert_eq!(capture.post_process_support, renderer_support);
        assert_eq!(
            capture
                .resource_dump
                .as_ref()
                .expect("resource dump is attached")
                .post_process_support,
            renderer_support
        );
    }

