    #[test]
    fn material_dependency_lookup_tracks_texture_and_sampler_users() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let texel = [255, 255, 255, 255];
        let texture_a = renderer
            .create_texture(TextureDesc {
                label: Some("dependency_texture_a"),
                dimension: TextureDimension::D2,
                width: 1,
                height: 1,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &texel,
                    bytes_per_row: 4,
                    rows_per_image: 1,
                }),
            })
            .unwrap();
        let texture_b = renderer
            .create_texture(TextureDesc {
                label: Some("dependency_texture_b"),
                dimension: TextureDimension::D2,
                width: 1,
                height: 1,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &texel,
                    bytes_per_row: 4,
                    rows_per_image: 1,
                }),
            })
            .unwrap();
        let sampler = renderer.create_sampler(SamplerDesc::default()).unwrap();
        let standard = renderer
            .create_standard_material(StandardMaterialDesc {
                base_color_texture: Some(texture_a),
                ..StandardMaterialDesc::default()
            })
            .unwrap();
        let shader = renderer
            .create_shader(ShaderDesc {
                label: Some("dependency_shader"),
                source: ShaderSource::Wgsl(
                    "@vertex fn vs_main() -> @builtin(position) vec4<f32> { return vec4<f32>(0.0, 0.0, 0.0, 1.0); }\n@fragment fn fs_main() -> @location(0) vec4<f32> { return vec4<f32>(1.0, 1.0, 1.0, 1.0); }",
                ),
                stages: ShaderStages::VERTEX | ShaderStages::FRAGMENT,
                entry_points: ShaderEntryPoints {
                    vertex: Some("vs_main"),
                    fragment: Some("fs_main"),
                    compute: None,
                },
                reflection: ShaderReflectionMode::Explicit(ShaderInterfaceDesc {
                    resources: vec![
                        ShaderResourceBinding {
                            name: "albedo".to_owned(),
                            group: 0,
                            binding: 0,
                            binding_class: BindingClass::Texture,
                            visibility: ShaderStages::FRAGMENT,
                            ty: BindingType::Texture(TextureDimension::D2),
                        },
                        ShaderResourceBinding {
                            name: "linear".to_owned(),
                            group: 0,
                            binding: 1,
                            binding_class: BindingClass::Sampler,
                            visibility: ShaderStages::FRAGMENT,
                            ty: BindingType::Sampler,
                        },
                    ],
                    push_constants: Vec::new(),
                    vertex_inputs: Vec::new(),
                }),
                features: ShaderFeatureSet::default(),
                hot_reload_key: None,
            })
            .unwrap();
        let template = renderer
            .create_material_template(MaterialTemplateDesc {
                label: Some("dependency_template".to_owned()),
                shader,
                domain: MaterialDomain::Opaque,
                render_state: RenderStateDesc { depth_write: true },
                parameter_schema: MaterialParameterSchema {
                    parameters: vec!["albedo".to_owned(), "linear".to_owned()],
                },
                passes: MaterialPassFlags::FORWARD,
            })
            .unwrap();
        let reflected = renderer
            .create_material(MaterialDesc {
                label: Some("dependency_material".to_owned()),
                template,
                parameters: vec![
                    MaterialParameter {
                        name: "albedo".to_owned(),
                        value: MaterialParameterValue::Texture(texture_b),
                    },
                    MaterialParameter {
                        name: "linear".to_owned(),
                        value: MaterialParameterValue::Sampler(sampler),
                    },
                ],
                overrides: MaterialOverrides::default(),
            })
            .unwrap();

        assert_eq!(
            renderer.materials_referencing_texture(texture_a),
            vec![standard]
        );
        assert_eq!(
            renderer.materials_referencing_texture(texture_b),
            vec![reflected]
        );
        assert_eq!(
            renderer.materials_referencing_sampler(sampler),
            vec![reflected]
        );
    }

