    #[test]
    fn render_targets_are_validated_and_can_back_offscreen_views() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let color = renderer
            .create_texture(TextureDesc {
                label: Some("offscreen_color"),
                dimension: TextureDimension::D2,
                width: 8,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET | TextureUsage::SAMPLED,
                initial_data: None,
            })
            .unwrap();
        let depth = renderer
            .create_texture(TextureDesc {
                label: Some("offscreen_depth"),
                dimension: TextureDimension::D2,
                width: 8,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Depth32Float,
                usage: TextureUsage::DEPTH_STENCIL,
                initial_data: None,
            })
            .unwrap();
        let render_target = renderer
            .create_render_target(RenderTargetDesc {
                label: Some("offscreen".to_owned()),
                color,
                depth: Some(depth),
                width: 8,
                height: 4,
                samples: 1,
            })
            .unwrap();
        let scene = renderer
            .create_scene(SceneDesc {
                label: Some("scene".to_owned()),
                max_objects_hint: None,
                max_lights_hint: None,
                enable_gpu_culling: false,
                enable_occlusion_culling: false,
            })
            .unwrap();
        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        let view = frame
            .render_view(ViewDesc {
                label: Some("offscreen_view".to_owned()),
                scene,
                camera: CameraDesc {
                    label: None,
                    transform: IDENTITY_MAT4,
                    projection: Projection::Orthographic {
                        width: 1.0,
                        height: 1.0,
                        near: 0.0,
                        far: 10.0,
                        reverse_z: false,
                    },
                    exposure: Exposure::Auto,
                    clear: ClearOptions::ColorDepth(Color::BLACK),
                    viewport: None,
                    scissor: None,
                    jitter: None,
                    previous_view_proj: None,
                    flags: CameraFlags::MAIN,
                },
                target: RenderTarget::External(render_target),
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings {
                    hdr: false,
                    bloom: false,
                    taa: false,
                    fxaa: false,
                    ssao: false,
                    ssr: false,
                    depth_of_field: false,
                    motion_blur: false,
                    variable_rate_shading: false,
                    bindless_textures: false,
                    mesh_shaders: false,
                    virtual_texturing: false,
                    ray_tracing: false,
                    color_grading: ColorGradingMode::None,
                },
                layers: RenderLayerMask::all(),
                graph_extensions: Vec::new(),
            })
            .unwrap();
        let stats = frame.finish().unwrap();

        assert_eq!(view.kind_tag(), ResourceKind::View.tag());
        assert_eq!(stats.graph.pass_count, 6);
        assert_eq!(
            renderer.resource_status(render_target),
            Some(ResourceStatus::Ready)
        );
        assert_eq!(renderer.render_target_desc(render_target).unwrap().width, 8);

        let layered_color = renderer
            .create_texture(TextureDesc {
                label: Some("layered_color"),
                dimension: TextureDimension::D2Array,
                width: 8,
                height: 4,
                depth_or_layers: 2,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET,
                initial_data: None,
            })
            .unwrap();
        assert!(matches!(
            renderer.create_render_target(RenderTargetDesc {
                label: None,
                color: layered_color,
                depth: None,
                width: 8,
                height: 4,
                samples: 1,
            }),
            Err(RendererError::Validation(_))
        ));

        let mipmapped_color = renderer
            .create_texture(TextureDesc {
                label: Some("mipmapped_color"),
                dimension: TextureDimension::D2,
                width: 8,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 2,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET,
                initial_data: None,
            })
            .unwrap();
        assert!(matches!(
            renderer.create_render_target(RenderTargetDesc {
                label: None,
                color: mipmapped_color,
                depth: None,
                width: 8,
                height: 4,
                samples: 1,
            }),
            Err(RendererError::Validation(_))
        ));
    }

    #[test]
    fn external_render_target_rejects_destroyed_attachment_at_frame_time() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let color = renderer
            .create_texture(TextureDesc {
                label: Some("destroyed_external_target_color"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET | TextureUsage::SAMPLED,
                initial_data: None,
            })
            .unwrap();
        let render_target = renderer
            .create_render_target(RenderTargetDesc {
                label: Some("destroyed_external_target_attachment".to_owned()),
                color,
                depth: None,
                width: 4,
                height: 4,
                samples: 1,
            })
            .unwrap();
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();

        renderer.destroy(color).unwrap();
        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        let result = frame.render_view(ViewDesc {
            label: Some("destroyed_external_target_view".to_owned()),
            scene,
            camera: test_camera(),
            target: RenderTarget::External(render_target),
            render_path: RenderPath::Forward,
            quality: ViewQualitySettings::default(),
            layers: RenderLayerMask::all(),
            graph_extensions: Vec::new(),
        });

        assert!(matches!(
            result,
            Err(RendererError::InvalidHandle {
                kind: ResourceKind::Texture,
                raw
            }) if raw == color.raw().get()
        ));
        drop(frame);
        assert_eq!(
            renderer.resource_status(color),
            Some(ResourceStatus::DestroyQueued)
        );
        assert_eq!(
            renderer.resource_status(render_target),
            Some(ResourceStatus::Ready)
        );
    }

