    #[test]
    fn render_targets_must_match_renderer_msaa_samples() {
        let mut renderer = Renderer::new_headless(RendererConfig {
            msaa_samples: 4,
            ..RendererConfig::default()
        });
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let single_sample_target = renderer
            .create_texture(TextureDesc {
                label: Some("single_sample_target"),
                dimension: TextureDimension::D2,
                width: 8,
                height: 8,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET,
                initial_data: None,
            })
            .unwrap();
        let single_sample_view = renderer
            .create_texture(TextureDesc {
                label: Some("single_sample_view_target"),
                dimension: TextureDimension::D2Array,
                width: 8,
                height: 8,
                depth_or_layers: 2,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET,
                initial_data: None,
            })
            .unwrap();
        let view = |target| ViewDesc {
            label: Some("msaa_target_validation".to_owned()),
            scene,
            camera: test_camera(),
            target,
            render_path: RenderPath::Forward,
            quality: ViewQualitySettings::default(),
            layers: RenderLayerMask::all(),
            graph_extensions: Vec::new(),
        };

        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        assert!(matches!(
            frame.render_view(view(RenderTarget::Texture(single_sample_target))),
            Err(RendererError::Validation(_))
        ));

        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        assert!(matches!(
            frame.render_view(view(RenderTarget::TextureView(TextureViewDesc {
                texture: single_sample_view,
                base_mip: 0,
                mip_count: 1,
                base_layer: 0,
                layer_count: 1,
            }))),
            Err(RendererError::Validation(_))
        ));
        drop(frame);

        let multisampled_color = renderer
            .create_texture(TextureDesc {
                label: Some("multisampled_color"),
                dimension: TextureDimension::D2,
                width: 8,
                height: 8,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 4,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET,
                initial_data: None,
            })
            .unwrap();
        assert!(matches!(
            renderer.create_render_target(RenderTargetDesc {
                label: Some("mismatched_external_target".to_owned()),
                color: multisampled_color,
                depth: None,
                width: 8,
                height: 8,
                samples: 1,
            }),
            Err(RendererError::Validation(_))
        ));

        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(view(RenderTarget::Texture(multisampled_color)))
            .unwrap();
    }

