    #[test]
    fn execute_graph_to_resources_uploads_imported_texture_subregions() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let subregion_texel = vec![200, 100, 50, 255];
        let updated_texture = (1_u8..=64).collect::<Vec<_>>();
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("subregion_public_texture"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        renderer
            .update_texture(
                texture,
                TextureUpdate {
                    subresource: TextureSubresource {
                        mip_level: 0,
                        array_layer: 0,
                    },
                    region: TextureRegion {
                        offset: [1, 1, 0],
                        extent: [1, 1, 1],
                    },
                    bytes_per_row: 4,
                    rows_per_image: 1,
                    data: &subregion_texel,
                },
            )
            .unwrap();
        let mut graph = RenderGraphBuilder::default();
        let imported_texture = graph.import_texture(
            "subregion_imported_texture",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        let pass_subregion_texel = subregion_texel.clone();
        let pass_updated_texture = updated_texture.clone();
        graph
            .add_pass("read_subregion_upload_and_write_full_texture")
            .read_texture(imported_texture, TextureReadUsage::CopySrc)
            .write_texture(imported_texture, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_texture = ctx.rhi_texture(imported_texture)?;
                let before_texture = ctx.rhi_device()?.read_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 4,
                        height: 4,
                    },
                )?;
                if &before_texture[0..4] != [0, 0, 0, 0].as_slice() {
                    return Err(RendererError::Validation(
                        "imported texture subregion upload unexpectedly filled texel 0,0"
                            .to_owned(),
                    ));
                }
                let subregion_offset = ((1 * 4 + 1) * 4) as usize;
                if before_texture[subregion_offset..subregion_offset + 4] != pass_subregion_texel {
                    return Err(RendererError::Validation(
                        "imported texture subregion bytes were not uploaded at the declared offset"
                            .to_owned(),
                    ));
                }
                ctx.rhi_device()?.write_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 4,
                        height: 4,
                    },
                    &pass_updated_texture,
                )?;
                Ok(())
            });
        graph.export_texture("subregion_imported_texture_output", imported_texture);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        assert!(execution
            .exports
            .all_texture_exports_complete_subresource_coverage());
        assert_eq!(
            execution
                .exports
                .texture_exports_with_incomplete_subresource_coverage(),
            0
        );
        assert!(!execution.exports.has_incomplete_export_coverage());
        let texture_export = execution
            .exports
            .texture_export("subregion_imported_texture_output")
            .expect("subregion imported texture export is present");
        assert_eq!(texture_export.texture, texture);
        assert_eq!(
            texture_export.source,
            RendererGraphExportSource::ImportedPublic
        );
        assert!(!texture_export.promoted);
        assert_eq!(texture_export.width, 4);
        assert_eq!(texture_export.height, 4);
        assert_eq!(texture_export.subresources.len(), 1);
        assert_eq!(texture_export.subresources[0].byte_len, 4 * 4 * 4);
        assert!(texture_export.complete_subresource_coverage);
        assert_eq!(
            renderer.texture_bytes(texture),
            Some(updated_texture.as_slice())
        );
    }

    fn rgba8_region_bytes(
        source: &[u8],
        source_width: u32,
        x: u32,
        y: u32,
        width: u32,
        height: u32,
    ) -> Vec<u8> {
        let source_width = source_width as usize;
        let x = x as usize;
        let y = y as usize;
        let width = width as usize;
        let height = height as usize;
        let mut region = Vec::with_capacity(width * height * 4);
        for row in y..y + height {
            let start = (row * source_width + x) * 4;
            region.extend_from_slice(&source[start..start + width * 4]);
        }
        region
    }

    #[test]
    fn execute_graph_to_resources_promotes_partial_texture_export_regions() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let graph_texture_bytes = (1_u8..=64).collect::<Vec<_>>();
        let expected_region = rgba8_region_bytes(&graph_texture_bytes, 4, 1, 1, 2, 2);
        let mut graph = RenderGraphBuilder::default();
        let texture = graph.create_texture(GraphTextureDesc {
            label: Some("partial_transient_texture".to_owned()),
            width: 4,
            height: 4,
            format: TextureFormat::Rgba8Unorm,
        });
        let pass_texture_bytes = graph_texture_bytes.clone();
        graph
            .add_pass("write_partial_transient_texture_source")
            .write_texture(texture, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(texture)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 4,
                        height: 4,
                    },
                    &pass_texture_bytes,
                )?;
                Ok(())
            });
        graph.export_texture_region("partial_texture_output", texture, 1, 1, 2, 2);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        assert_eq!(execution.stats.exported_texture_regions, 1);
        assert_eq!(
            execution.stats.exported_texture_region_labels,
            vec!["partial_texture_output".to_owned()]
        );
        assert_eq!(
            execution
                .exports
                .texture_exports_with_incomplete_subresource_coverage(),
            1
        );
        assert_eq!(execution.exports.texture_exports_with_regions(), 1);
        assert!(execution.exports.has_texture_region_exports());
        assert!(!execution
            .exports
            .all_texture_exports_complete_subresource_coverage());
        assert!(execution.exports.has_incomplete_export_coverage());
        let texture_export = execution
            .exports
            .texture_export("partial_texture_output")
            .expect("partial texture export is promoted");
        assert!(texture_export.promoted);
        assert_eq!(
            texture_export.region,
            Some(RhiTextureExportRegion {
                x: 1,
                y: 1,
                width: 2,
                height: 2,
            })
        );
        assert_eq!(
            texture_export.source,
            RendererGraphExportSource::PromotedTransient
        );
        assert_eq!(texture_export.width, 4);
        assert_eq!(texture_export.height, 4);
        assert_eq!(texture_export.subresources.len(), 1);
        assert_eq!(texture_export.subresources[0].mip_level, 0);
        assert_eq!(texture_export.subresources[0].base_layer, 0);
        assert_eq!(texture_export.subresources[0].layer_count, 1);
        assert_eq!(texture_export.subresources[0].width, 2);
        assert_eq!(texture_export.subresources[0].height, 2);
        assert_eq!(texture_export.subresources[0].offset, [1, 1, 0]);
        assert_eq!(texture_export.subresources[0].byte_offset, 0);
        assert_eq!(texture_export.subresources[0].byte_len, 2 * 2 * 4);
        assert_eq!(texture_export.subresources[0].bytes_per_row, 2 * 4);
        assert_eq!(texture_export.subresources[0].rows_per_image, 2);
        assert!(!texture_export.complete_subresource_coverage);
        assert_eq!(
            renderer.texture_bytes(texture_export.texture),
            Some(expected_region.as_slice())
        );
        let texture_info = renderer.texture_info(texture_export.texture).unwrap();
        assert_eq!(texture_info.width, 4);
        assert_eq!(texture_info.height, 4);
        assert_eq!(texture_info.subresources.len(), 1);
        assert_eq!(texture_info.subresources[0].width, 2);
        assert_eq!(texture_info.subresources[0].height, 2);
        assert_eq!(texture_info.subresources[0].offset, [1, 1, 0]);
        assert!(!texture_info.complete_subresource_coverage);
    }

