    #[test]
    fn execute_graph_to_resources_rejects_imported_texture_export_regions_out_of_bounds() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("region_checked_public_texture"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        let mut graph = RenderGraphBuilder::default();
        let imported_texture = graph.import_texture(
            "region_checked_imported_texture",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        graph
            .add_pass("region_checked_imported_texture_pass")
            .read_texture(imported_texture, TextureReadUsage::CopySrc)
            .execute(|_| {
                Err(RendererError::Validation(
                    "texture region preflight should reject before graph execution".to_owned(),
                ))
            });
        graph.export_texture_region(
            "region_checked_imported_texture_output",
            imported_texture,
            3,
            3,
            2,
            2,
        );

        let err = renderer.execute_graph_to_resources(&mut graph).unwrap_err();

        assert!(matches!(
            err,
            RendererError::RenderGraphValidation(message)
                if message.contains("public graph exported texture 'region_checked_imported_texture_output'")
                    && message.contains("region exceeds represented texture extent")
        ));
    }

