    #[test]
    fn execute_graph_to_resources_uploads_imported_buffer_subrange_updates() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let updated_subrange = vec![9, 8, 7];
        let second_subrange = vec![5];
        let expected_import_bytes = vec![0, 0, 9, 8, 7, 0, 5, 0];
        let graph_updated_bytes = vec![1, 2, 3, 4, 5, 6, 7, 8];
        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("subrange_public_buffer"),
                size: 8,
                usage: BufferUsage::COPY_SRC | BufferUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        renderer
            .update_buffer(
                buffer,
                BufferUpdate {
                    byte_offset: 2,
                    data: &updated_subrange,
                },
            )
            .unwrap();
        renderer
            .update_buffer(
                buffer,
                BufferUpdate {
                    byte_offset: 6,
                    data: &second_subrange,
                },
            )
            .unwrap();
        let pre_graph_buffer_info = renderer.buffer_info(buffer).unwrap();
        assert_eq!(pre_graph_buffer_info.byte_offset, 2);
        assert_eq!(pre_graph_buffer_info.byte_len, 5);
        assert_eq!(pre_graph_buffer_info.represented_byte_len(), 4);
        assert_eq!(pre_graph_buffer_info.byte_ranges.len(), 2);
        assert_eq!(pre_graph_buffer_info.byte_ranges[0].byte_offset, 2);
        assert_eq!(pre_graph_buffer_info.byte_ranges[0].byte_len, 3);
        assert_eq!(pre_graph_buffer_info.byte_ranges[1].byte_offset, 6);
        assert_eq!(pre_graph_buffer_info.byte_ranges[1].byte_len, 1);
        assert!(!pre_graph_buffer_info.complete_byte_coverage);
        assert!(!pre_graph_buffer_info.has_complete_byte_coverage());
        let pre_graph_buffer_support = renderer.graph_buffer_import_support(buffer).unwrap();
        assert_eq!(pre_graph_buffer_support.byte_offset, 2);
        assert_eq!(pre_graph_buffer_support.byte_len, 5);
        assert_eq!(pre_graph_buffer_support.represented_byte_len(), 4);
        assert_eq!(pre_graph_buffer_support.byte_ranges.len(), 2);
        assert_eq!(pre_graph_buffer_support.byte_ranges[0].byte_offset, 2);
        assert_eq!(pre_graph_buffer_support.byte_ranges[0].byte_len, 3);
        assert_eq!(pre_graph_buffer_support.byte_ranges[1].byte_offset, 6);
        assert_eq!(pre_graph_buffer_support.byte_ranges[1].byte_len, 1);
        assert!(pre_graph_buffer_support.has_disjoint_byte_ranges());
        assert!(!pre_graph_buffer_support.complete_byte_coverage);

        let mut graph = RenderGraphBuilder::default();
        let imported_buffer = graph.import_buffer(
            "subrange_imported_buffer",
            buffer,
            GraphBufferUsage::COPY_SRC | GraphBufferUsage::COPY_DST,
        );
        let pass_expected_import_bytes = expected_import_bytes.clone();
        let pass_graph_updated_bytes = graph_updated_bytes.clone();
        graph
            .add_pass("read_subrange_buffer_update_and_write_full_buffer")
            .read_buffer(imported_buffer, BufferReadUsage::CopySrc)
            .write_buffer(imported_buffer, BufferWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_buffer = ctx.rhi_buffer(imported_buffer)?;
                let before_buffer = ctx.rhi_device()?.read_buffer(rhi_buffer, 0, 8)?;
                if before_buffer != pass_expected_import_bytes {
                    return Err(RendererError::Validation(
                        "imported buffer subrange update was not visible before graph execution"
                            .to_owned(),
                    ));
                }
                ctx.rhi_device()?
                    .write_buffer(rhi_buffer, 0, &pass_graph_updated_bytes)?;
                Ok(())
            });
        graph.export_buffer_ranges(
            "subrange_imported_buffer_output",
            imported_buffer,
            [(3, 2), (2, 1), (6, 1)],
        );
        let graph_support = renderer.graph_import_support(&graph).unwrap();
        assert_eq!(
            graph_support.buffer_imports_with_incomplete_byte_coverage(),
            1
        );
        assert_eq!(graph_support.buffer_imports_with_disjoint_byte_ranges(), 1);
        assert_eq!(graph_support.buffer_import_represented_bytes(), 4);
        assert!(!graph_support.all_buffer_imports_complete_byte_coverage());
        assert!(graph_support.has_incomplete_import_coverage());

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        assert!(!execution
            .exports
            .all_buffer_exports_complete_byte_coverage());
        assert_eq!(
            execution
                .exports
                .buffer_exports_with_incomplete_byte_coverage(),
            1
        );
        assert_eq!(
            execution.exports.buffer_exports_with_disjoint_byte_ranges(),
            1
        );
        assert_eq!(execution.exports.buffer_export_represented_bytes(), 4);
        assert!(execution.exports.has_incomplete_export_coverage());
        let buffer_export = execution
            .exports
            .buffer_export("subrange_imported_buffer_output")
            .expect("subrange imported buffer export is present");
        assert_eq!(buffer_export.buffer, buffer);
        assert_eq!(
            buffer_export.source,
            RendererGraphExportSource::ImportedPublic
        );
        assert!(!buffer_export.promoted);
        assert_eq!(buffer_export.size, 8);
        assert_eq!(buffer_export.byte_offset, 2);
        assert_eq!(buffer_export.byte_len, 5);
        assert_eq!(buffer_export.byte_ranges.len(), 2);
        assert_eq!(buffer_export.byte_ranges[0].byte_offset, 2);
        assert_eq!(buffer_export.byte_ranges[0].byte_len, 3);
        assert_eq!(buffer_export.byte_ranges[1].byte_offset, 6);
        assert_eq!(buffer_export.byte_ranges[1].byte_len, 1);
        assert_eq!(buffer_export.represented_byte_len(), 4);
        assert!(buffer_export.has_disjoint_byte_ranges());
        assert!(!buffer_export.complete_byte_coverage);
        assert_eq!(
            renderer.buffer_bytes(buffer),
            Some([0, 0, 3, 4, 5, 0, 7, 0].as_slice())
        );
        let buffer_info = renderer.buffer_info(buffer).unwrap();
        assert_eq!(buffer_info.size, 8);
        assert_eq!(buffer_info.byte_offset, 2);
        assert_eq!(buffer_info.byte_len, 5);
        assert_eq!(buffer_info.represented_byte_len(), 4);
        assert!(!buffer_info.complete_byte_coverage);
        assert!(!buffer_info.has_complete_byte_coverage());
    }

    #[test]
    fn execute_graph_to_resources_promotes_partial_buffer_export_ranges() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let graph_bytes = vec![1, 2, 3, 4, 5, 6, 7, 8];
        let mut graph = RenderGraphBuilder::default();
        let buffer = graph.create_buffer(GraphBufferDesc {
            label: Some("partial_transient_buffer".to_owned()),
            size: 8,
        });
        let pass_graph_bytes = graph_bytes.clone();
        graph
            .add_pass("write_partial_transient_buffer_source")
            .write_buffer(buffer, BufferWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_buffer = ctx.rhi_buffer(buffer)?;
                ctx.rhi_device()?
                    .write_buffer(rhi_buffer, 0, &pass_graph_bytes)?;
                Ok(())
            });
        graph.export_buffer_ranges("partial_transient_buffer_output", buffer, [(2, 2), (6, 1)]);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        assert_eq!(
            execution
                .exports
                .buffer_exports_with_incomplete_byte_coverage(),
            1
        );
        assert_eq!(
            execution.exports.buffer_exports_with_disjoint_byte_ranges(),
            1
        );
        assert_eq!(execution.exports.buffer_export_represented_bytes(), 3);
        assert!(!execution
            .exports
            .all_buffer_exports_complete_byte_coverage());
        let buffer_export = execution
            .exports
            .buffer_export("partial_transient_buffer_output")
            .expect("partial transient buffer export is present");
        assert!(buffer_export.promoted);
        assert_eq!(
            buffer_export.source,
            RendererGraphExportSource::PromotedTransient
        );
        assert_eq!(buffer_export.size, 8);
        assert_eq!(buffer_export.byte_offset, 2);
        assert_eq!(buffer_export.byte_len, 5);
        assert_eq!(buffer_export.byte_ranges.len(), 2);
        assert_eq!(buffer_export.byte_ranges[0].byte_offset, 2);
        assert_eq!(buffer_export.byte_ranges[0].byte_len, 2);
        assert_eq!(buffer_export.byte_ranges[1].byte_offset, 6);
        assert_eq!(buffer_export.byte_ranges[1].byte_len, 1);
        assert_eq!(buffer_export.represented_byte_len(), 3);
        assert!(buffer_export.has_disjoint_byte_ranges());
        assert!(!buffer_export.complete_byte_coverage);
        assert_eq!(
            renderer.buffer_bytes(buffer_export.buffer),
            Some([0, 0, 3, 4, 0, 0, 7, 0].as_slice())
        );
        let buffer_info = renderer.buffer_info(buffer_export.buffer).unwrap();
        assert_eq!(buffer_info.byte_offset, 2);
        assert_eq!(buffer_info.byte_len, 5);
        assert_eq!(buffer_info.represented_byte_len(), 3);
        assert_eq!(buffer_info.byte_ranges.len(), 2);
        assert!(!buffer_info.complete_byte_coverage);
    }

