    #[test]
    fn execute_graph_to_resources_uploads_and_writes_back_depth_imports() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let initial_depth_values = vec![0.1_f32, 0.2, 0.3, 0.4];
        let updated_depth_values = vec![0.9_f32, 0.8, 0.7, 0.6];
        let initial_depth_bytes = initial_depth_values
            .iter()
            .flat_map(|value| value.to_le_bytes())
            .collect::<Vec<_>>();
        let updated_depth_bytes = updated_depth_values
            .iter()
            .flat_map(|value| value.to_le_bytes())
            .collect::<Vec<_>>();
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("imported_public_depth"),
                dimension: TextureDimension::D2,
                width: 2,
                height: 2,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Depth32Float,
                usage: TextureUsage::DEPTH_STENCIL
                    | TextureUsage::COPY_SRC
                    | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &initial_depth_bytes,
                    bytes_per_row: 8,
                    rows_per_image: 2,
                }),
            })
            .unwrap();

        let mut graph = RenderGraphBuilder::default();
        let imported_depth = graph.import_texture(
            "imported_depth",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        let pass_initial_depth_values = initial_depth_values.clone();
        let pass_updated_depth_values = updated_depth_values.clone();
        graph
            .add_pass("read_write_imported_depth")
            .read_texture(imported_depth, TextureReadUsage::CopySrc)
            .write_texture(imported_depth, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_texture = ctx.rhi_texture(imported_depth)?;
                let before_depth = ctx.rhi_device()?.read_texture_depth32f(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                )?;
                if before_depth != pass_initial_depth_values {
                    return Err(RendererError::Validation(
                        "imported depth texture values were not uploaded before graph execution"
                            .to_owned(),
                    ));
                }
                ctx.rhi_device()?.write_texture_depth32f(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                    &pass_updated_depth_values,
                )?;
                Ok(())
            });
        graph.export_texture("imported_depth_output", imported_depth);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        let texture_export = execution
            .exports
            .texture_export("imported_depth_output")
            .expect("imported depth export is present");
        assert_eq!(texture_export.texture, texture);
        assert!(!texture_export.promoted);
        assert_eq!(
            renderer.texture_bytes(texture),
            Some(updated_depth_bytes.as_slice())
        );
        let texture_info = renderer.texture_info(texture).unwrap();
        assert_eq!(texture_info.format, TextureFormat::Depth32Float);
        assert!(texture_info.usage.contains(TextureUsage::DEPTH_STENCIL));
    }

    #[test]
