    #[test]
    fn execute_graph_to_resources_uploads_non_base_mip_subregions() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let initial_texel = vec![200, 100, 50, 255];
        let updated_mip = vec![1, 2, 3, 255, 4, 5, 6, 255, 7, 8, 9, 255, 10, 11, 12, 255];
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("imported_public_mip1_subregion_texture"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 3,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        renderer
            .update_texture(
                texture,
                TextureUpdate {
                    subresource: TextureSubresource {
                        mip_level: 1,
                        array_layer: 0,
                    },
                    region: TextureRegion {
                        offset: [1, 1, 0],
                        extent: [1, 1, 1],
                    },
                    bytes_per_row: 4,
                    rows_per_image: 1,
                    data: &initial_texel,
                },
            )
            .unwrap();
        let import_support = renderer.graph_texture_import_support(texture).unwrap();
        assert_eq!(import_support.subresources.len(), 1);
        assert_eq!(import_support.subresources[0].mip_level, 1);
        assert_eq!(import_support.subresources[0].offset, [1, 1, 0]);
        assert_eq!(import_support.subresources[0].width, 1);
        assert_eq!(import_support.subresources[0].height, 1);
        assert_eq!(import_support.subresources[0].byte_len, 4);

        let mut graph = RenderGraphBuilder::default();
        let imported_texture = graph.import_texture(
            "imported_mip1_subregion_texture",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        let pass_initial_texel = initial_texel.clone();
        let pass_updated_mip = updated_mip.clone();
        graph
            .add_pass("read_mip1_subregion_and_write_full_mip")
            .read_texture(imported_texture, TextureReadUsage::CopySrc)
            .write_texture(imported_texture, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_texture = ctx.rhi_texture(imported_texture)?;
                let before_texture = ctx.rhi_device()?.read_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                )?;
                if before_texture[0..4] != [0, 0, 0, 0] {
                    return Err(RendererError::Validation(
                        "imported non-base mip subregion unexpectedly filled texel 0,0"
                            .to_owned(),
                    ));
                }
                if &before_texture[12..16] != pass_initial_texel.as_slice() {
                    return Err(RendererError::Validation(
                        "imported non-base mip subregion bytes were not uploaded at the declared offset"
                            .to_owned(),
                    ));
                }
                ctx.rhi_device()?.write_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                    &pass_updated_mip,
                )?;
                Ok(())
            });
        graph.export_texture("imported_mip1_subregion_texture_output", imported_texture);
        let graph_support = renderer.graph_import_support(&graph).unwrap();
        assert_eq!(graph_support.textures.len(), 1);
        assert_eq!(graph_support.textures[0].subresources.len(), 1);
        assert_eq!(graph_support.textures[0].subresources[0].offset, [1, 1, 0]);
        assert_eq!(graph_support.textures[0].subresources[0].width, 1);
        assert_eq!(graph_support.textures[0].subresources[0].height, 1);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        assert!(execution.exports.has_incomplete_export_coverage());
        let texture_export = execution
            .exports
            .texture_export("imported_mip1_subregion_texture_output")
            .expect("imported non-base mip subregion texture export is present");
        assert_eq!(texture_export.texture, texture);
        assert_eq!(
            texture_export.source,
            RendererGraphExportSource::ImportedPublic
        );
        assert!(!texture_export.promoted);
        assert_eq!(texture_export.mip_levels, 3);
        assert_eq!(texture_export.subresources.len(), 1);
        assert_eq!(texture_export.subresources[0].mip_level, 1);
        assert_eq!(texture_export.subresources[0].width, 2);
        assert_eq!(texture_export.subresources[0].height, 2);
        assert_eq!(texture_export.subresources[0].byte_len, 2 * 2 * 4);
        assert!(!texture_export.complete_mip_coverage);
        assert!(texture_export.complete_layer_coverage);
        assert!(!texture_export.complete_subresource_coverage);
        assert_eq!(
            renderer.texture_bytes(texture),
            Some(updated_mip.as_slice())
        );
    }

    #[test]
    fn execute_graph_to_resources_uploads_generated_mip_base_imports() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let initial_base = (0_u8..64).collect::<Vec<_>>();
        let updated_base = (96_u8..160).collect::<Vec<_>>();
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("generated_mip_public_import"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &initial_base,
                    bytes_per_row: 16,
                    rows_per_image: 4,
                }),
            })
            .unwrap();
        renderer.generate_mips(texture).unwrap();
        let generated_info = renderer.texture_info(texture).unwrap();
        assert_eq!(generated_info.mip_levels, 3);
        assert!(generated_info.mips_generated);
        assert!(renderer.texture_bytes(texture).unwrap().len() > initial_base.len());
        let import_support = renderer.graph_texture_import_support(texture).unwrap();
        assert!(import_support.supported);
        assert_eq!(import_support.mip_levels, 3);
        assert_eq!(import_support.represented_mip, 0);
        assert_eq!(import_support.represented_width, 4);
        assert_eq!(import_support.represented_height, 7);
        assert_eq!(import_support.represented_layer_count, 1);
        assert_eq!(
            import_support.represented_byte_len,
            4 * 4 * 4 + 2 * 2 * 4 + 1 * 1 * 4
        );
        assert_eq!(import_support.subresources.len(), 3);
        assert_eq!(import_support.subresources[0].mip_level, 0);
        assert_eq!(import_support.subresources[0].byte_offset, 0);
        assert_eq!(import_support.subresources[0].byte_len, 4 * 4 * 4);
        assert_eq!(import_support.subresources[1].mip_level, 1);
        assert_eq!(import_support.subresources[1].byte_offset, 4 * 4 * 4);
        assert_eq!(import_support.subresources[1].byte_len, 2 * 2 * 4);
        assert_eq!(import_support.subresources[2].mip_level, 2);
        assert_eq!(
            import_support.subresources[2].byte_offset,
            4 * 4 * 4 + 2 * 2 * 4
        );
        assert_eq!(import_support.subresources[2].byte_len, 1 * 1 * 4);
        assert_eq!(
            import_support.subresource_byte_len(),
            4 * 4 * 4 + 2 * 2 * 4 + 1 * 1 * 4
        );
        assert!(import_support.has_packed_subresources());
        assert!(import_support.complete_mip_coverage);
        assert!(import_support.complete_layer_coverage);
        assert!(import_support.complete_subresource_coverage);

        let mut graph = RenderGraphBuilder::default();
        let imported_texture = graph.import_texture(
            "generated_mip_imported_texture",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        let pass_initial_base = initial_base.clone();
        let pass_initial_mip1 = generate_next_rgba8_mip(&initial_base, 4, 4, 2, 2);
        let pass_initial_mip2 = generate_next_rgba8_mip(&pass_initial_mip1, 2, 2, 1, 1);
        let pass_updated_base = updated_base.clone();
        graph
            .add_pass("read_write_generated_mip_base_import")
            .read_texture(imported_texture, TextureReadUsage::CopySrc)
            .write_texture(imported_texture, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_texture = ctx.rhi_texture(imported_texture)?;
                let before_texture = ctx.rhi_device()?.read_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 4,
                        height: 4,
                    },
                )?;
                if before_texture != pass_initial_base {
                    return Err(RendererError::Validation(
                        "generated mip texture base mip was not uploaded before graph execution"
                            .to_owned(),
                    ));
                }
                let before_mip1 = ctx.rhi_device()?.read_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 4,
                        width: 2,
                        height: 2,
                    },
                )?;
                if before_mip1 != pass_initial_mip1 {
                    return Err(RendererError::Validation(
                        "generated mip texture mip 1 was not uploaded before graph execution"
                            .to_owned(),
                    ));
                }
                let before_mip2 = ctx.rhi_device()?.read_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 6,
                        width: 1,
                        height: 1,
                    },
                )?;
                if before_mip2 != pass_initial_mip2 {
                    return Err(RendererError::Validation(
                        "generated mip texture mip 2 was not uploaded before graph execution"
                            .to_owned(),
                    ));
                }
                ctx.rhi_device()?.write_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 4,
                        height: 4,
                    },
                    &pass_updated_base,
                )?;
                Ok(())
            });
        graph.export_texture("generated_mip_imported_texture_output", imported_texture);
        let graph_support = renderer.graph_import_support(&graph).unwrap();
        assert_eq!(graph_support.texture_imports_with_packed_subresources(), 1);
        assert_eq!(
            graph_support.texture_imports_with_incomplete_subresource_coverage(),
            0
        );
        assert_eq!(
            graph_support.texture_import_subresource_bytes(),
            4 * 4 * 4 + 2 * 2 * 4 + 1 * 1 * 4
        );
        assert!(graph_support.all_texture_imports_complete_subresource_coverage());
        assert!(!graph_support.has_incomplete_import_coverage());

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        let texture_export = execution
            .exports
            .texture_export("generated_mip_imported_texture_output")
            .expect("generated mip imported texture export is present");
        let mip1 = generate_next_rgba8_mip(&updated_base, 4, 4, 2, 2);
        let mip2 = generate_next_rgba8_mip(&mip1, 2, 2, 1, 1);
        let mut expected_chain = updated_base.clone();
        expected_chain.extend_from_slice(&mip1);
        expected_chain.extend_from_slice(&mip2);
        assert_eq!(texture_export.texture, texture);
        assert!(!texture_export.promoted);
        assert_eq!(texture_export.subresources.len(), 3);
        assert_eq!(texture_export.subresources[0].mip_level, 0);
        assert_eq!(texture_export.subresources[0].byte_offset, 0);
        assert_eq!(texture_export.subresources[0].byte_len, 4 * 4 * 4);
        assert_eq!(texture_export.subresources[1].mip_level, 1);
        assert_eq!(texture_export.subresources[1].byte_offset, 4 * 4 * 4);
        assert_eq!(texture_export.subresources[1].byte_len, 2 * 2 * 4);
        assert_eq!(texture_export.subresources[2].mip_level, 2);
        assert_eq!(
            texture_export.subresources[2].byte_offset,
            4 * 4 * 4 + 2 * 2 * 4
        );
        assert_eq!(texture_export.subresources[2].byte_len, 1 * 1 * 4);
        assert!(texture_export.complete_mip_coverage);
        assert!(texture_export.complete_layer_coverage);
        assert!(texture_export.complete_subresource_coverage);
        assert_eq!(
            renderer.texture_bytes(texture),
            Some(expected_chain.as_slice())
        );
        let texture_info = renderer.texture_info(texture).unwrap();
        assert_eq!(texture_info.mip_levels, 3);
        assert!(texture_info.mips_generated);
    }

