    #[test]
    fn execute_graph_to_resources_rejects_generated_mip_texture_export_regions_outside_chain() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let initial_base = (0_u8..64).collect::<Vec<_>>();
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("generated_mip_region_checked_public_import"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::SAMPLED | TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &initial_base,
                    bytes_per_row: 16,
                    rows_per_image: 4,
                }),
            })
            .unwrap();
        renderer.generate_mips(texture).unwrap();
        let mut graph = RenderGraphBuilder::default();
        let imported_texture = graph.import_texture(
            "generated_mip_region_checked_imported_texture",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        graph
            .add_pass("generated_mip_region_checked_pass")
            .read_texture(imported_texture, TextureReadUsage::CopySrc)
            .execute(|_| {
                Err(RendererError::Validation(
                    "generated mip region preflight should reject before graph execution"
                        .to_owned(),
                ))
            });
        graph.export_texture_region(
            "generated_mip_region_checked_texture_output",
            imported_texture,
            0,
            7,
            2,
            1,
        );

        let err = renderer.execute_graph_to_resources(&mut graph).unwrap_err();

        assert!(matches!(
            err,
            RendererError::RenderGraphValidation(message)
                if message.contains("public graph exported texture 'generated_mip_region_checked_texture_output'")
                    && message.contains("region exceeds generated mip-chain extent")
        ));
    }

