        assert_eq!(texture_export.subresources[0].layer_count, 2);
        assert_eq!(texture_export.subresources[0].byte_offset, 0);
        assert_eq!(texture_export.subresources[0].byte_len, 4 * 4 * 2 * 4);
        assert_eq!(texture_export.subresources[1].mip_level, 1);
        assert_eq!(texture_export.subresources[1].layer_count, 2);
        assert_eq!(texture_export.subresources[1].byte_offset, 4 * 4 * 2 * 4);
        assert_eq!(texture_export.subresources[1].byte_len, 2 * 2 * 2 * 4);
        assert_eq!(texture_export.subresources[2].mip_level, 2);
        assert_eq!(texture_export.subresources[2].layer_count, 2);
