    #[test]
    fn execute_graph_to_resources_promotes_8bit_srgb_and_bgra_exports() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let mut graph = RenderGraphBuilder::default();
        let srgb = graph.create_texture(GraphTextureDesc {
            label: Some("transient_srgb_export".to_owned()),
            width: 2,
            height: 2,
            format: TextureFormat::Rgba8UnormSrgb,
        });
        let bgra = graph.create_texture(GraphTextureDesc {
            label: Some("transient_bgra_export".to_owned()),
            width: 2,
            height: 2,
            format: TextureFormat::Bgra8UnormSrgb,
        });
        let srgb_bytes = vec![
            32, 64, 96, 255, 48, 80, 112, 255, 64, 96, 128, 255, 80, 112, 144, 255,
        ];
        let bgra_bytes = vec![
            255, 96, 64, 255, 240, 112, 80, 255, 224, 128, 96, 255, 208, 144, 112, 255,
        ];
        let pass_srgb_bytes = srgb_bytes.clone();
        let pass_bgra_bytes = bgra_bytes.clone();
        graph
            .add_pass("write_8bit_color_exports")
            .write_texture(srgb, TextureWriteUsage::CopyDst)
            .write_texture(bgra, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(srgb)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                    &pass_srgb_bytes,
                )?;
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(bgra)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                    &pass_bgra_bytes,
                )?;
                Ok(())
            });
        graph.export_texture("srgb_output", srgb);
        graph.export_texture("bgra_output", bgra);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        assert_eq!(execution.stats.exported_textures, 2);
        let srgb_export = execution
            .exports
            .texture_export("srgb_output")
            .expect("sRGB texture export is promoted");
        assert!(srgb_export.promoted);
        let srgb_info = renderer.texture_info(srgb_export.texture).unwrap();
        assert_eq!(srgb_info.format, TextureFormat::Rgba8UnormSrgb);
        assert_eq!(
            renderer.texture_bytes(srgb_export.texture),
            Some(srgb_bytes.as_slice())
        );
        let bgra_export = execution
            .exports
            .texture_export("bgra_output")
            .expect("BGRA texture export is promoted");
        assert!(bgra_export.promoted);
        let bgra_info = renderer.texture_info(bgra_export.texture).unwrap();
        assert_eq!(bgra_info.format, TextureFormat::Bgra8UnormSrgb);
        assert_eq!(
            renderer.texture_bytes(bgra_export.texture),
            Some(bgra_bytes.as_slice())
        );
    }

