    #[test]
    fn execute_graph_to_resources_promotes_graph_created_mip_chain_texture_descs() {
        let cases = [
            ("d1", TextureDimension::D1, 4, 1, 1),
            ("d2", TextureDimension::D2, 4, 4, 1),
            ("d2_array", TextureDimension::D2Array, 4, 4, 2),
            ("d3", TextureDimension::D3, 4, 4, 4),
            ("cube", TextureDimension::Cube, 4, 4, 6),
            ("cube_array", TextureDimension::CubeArray, 4, 4, 12),
        ];

        for (case_index, (label, dimension, width, height, depth_or_layers)) in
            cases.into_iter().enumerate()
        {
            let mut renderer = Renderer::new_headless(RendererConfig::default());
            let mut graph = RenderGraphBuilder::default();
            let desc = TextureDesc {
                label: Some(label),
                dimension,
                width,
                height,
                depth_or_layers,
                mip_levels: 3,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_DST | TextureUsage::COPY_SRC,
                initial_data: None,
            };
            let support = RenderGraphBuilder::texture_desc_support(&desc);
            assert!(support.supported, "{label} support: {support:?}");
            assert_eq!(support.mip_levels, 3);
            let texture = graph
                .try_create_texture_from_desc(format!("transient_{label}_mips"), desc)
                .unwrap();

            let mut packed_y = 0_u32;
            let mut writes = Vec::new();
            let mut expected = Vec::new();
            for mip_level in 0..3 {
                let mip_width = mip_extent(width, mip_level);
                let mip_height = mip_extent(height, mip_level);
                let mip_layers = if matches!(dimension, TextureDimension::D3) {
                    mip_extent(depth_or_layers, mip_level)
                } else {
                    depth_or_layers
                };
                let flattened_height = mip_height * mip_layers;
                let byte_len = (mip_width * flattened_height * 4) as usize;
                let bytes = (0..byte_len)
                    .map(|value| ((value + case_index * 17 + mip_level as usize * 29) % 251) as u8)
                    .collect::<Vec<_>>();
                expected.extend_from_slice(&bytes);
                writes.push((packed_y, mip_width, flattened_height, bytes));
                packed_y += flattened_height;
            }

            graph
                .add_pass(format!("write_{label}_mip_chain_export"))
                .write_texture(texture, TextureWriteUsage::CopyDst)
                .execute(move |ctx| {
                    for (y, width, height, bytes) in &writes {
                        ctx.rhi_device()?.write_texture_rgba8(
                            ctx.rhi_texture(texture)?,
                            RhiTextureRegion {
                                x: 0,
                                y: *y,
                                width: *width,
                                height: *height,
                            },
                            bytes,
                        )?;
                    }
                    Ok(())
                });
            let export_label = format!("{label}_mip_output");
            graph.export_texture(&export_label, texture);

            let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

            let texture_export = execution
                .exports
                .texture_export(&export_label)
                .expect("mip-chain graph-created texture export is promoted");
            assert!(texture_export.promoted);
            assert_eq!(texture_export.dimension, dimension);
            assert_eq!(texture_export.width, width);
            assert_eq!(texture_export.height, height);
            assert_eq!(texture_export.depth_or_layers, depth_or_layers);
            assert_eq!(texture_export.mip_levels, 3);
            assert_eq!(texture_export.samples, 1);
            assert!(texture_export.has_packed_subresources());
            assert!(texture_export.complete_mip_coverage);
            assert!(texture_export.complete_layer_coverage);
            assert!(texture_export.complete_subresource_coverage);
            let texture_info = renderer.texture_info(texture_export.texture).unwrap();
            assert_eq!(texture_info.dimension, dimension);
            assert_eq!(texture_info.mip_levels, 3);
            assert_eq!(texture_info.subresources.len(), 3);
            assert!(texture_info.has_packed_subresources());
            assert!(texture_info.complete_subresource_coverage);
            assert_eq!(
                renderer.texture_bytes(texture_export.texture),
                Some(expected.as_slice())
            );
        }
    }

    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn execute_graph_to_resources_wgpu_promotes_graph_created_mip_chain_texture_desc() {
        let mut config = RendererConfig::default();
        config.backend = BackendPreference::Wgpu;
        let mut renderer = match block_on_ready(Renderer::new(config)) {
            Ok(renderer) => renderer,
            Err(error) => {
                eprintln!("skipping wgpu graph-created mip-chain transient export test: {error}");
                return;
            }
        };
        let mut graph = RenderGraphBuilder::default();
        let desc = TextureDesc {
            label: Some("wgpu_transient_mip_chain_desc"),
            dimension: TextureDimension::D2,
            width: 4,
            height: 4,
            depth_or_layers: 1,
            mip_levels: 3,
            samples: 1,
            format: TextureFormat::Rgba8Unorm,
            usage: TextureUsage::COPY_DST | TextureUsage::COPY_SRC,
            initial_data: None,
        };
        assert!(RenderGraphBuilder::texture_desc_support(&desc).supported);
        let texture = graph
            .try_create_texture_from_desc("wgpu_transient_mip_chain_export", desc)
            .unwrap();
        let base = (0..(4 * 4 * 4))
            .map(|value| ((value * 3 + 11) % 251) as u8)
            .collect::<Vec<_>>();
        let mip1 = (0..(2 * 2 * 4))
            .map(|value| ((value * 5 + 19) % 251) as u8)
            .collect::<Vec<_>>();
        let mip2 = (0..4)
            .map(|value| ((value * 7 + 23) % 251) as u8)
            .collect::<Vec<_>>();
        let expected = [base.as_slice(), mip1.as_slice(), mip2.as_slice()].concat();
        let pass_base = base.clone();
        let pass_mip1 = mip1.clone();
        let pass_mip2 = mip2.clone();
        graph
            .add_pass("wgpu_write_mip_chain_texture_export")
            .write_texture(texture, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(texture)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 4,
                        height: 4,
                    },
                    &pass_base,
                )?;
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(texture)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 4,
                        width: 2,
                        height: 2,
                    },
                    &pass_mip1,
                )?;
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(texture)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 6,
                        width: 1,
                        height: 1,
                    },
                    &pass_mip2,
                )?;
                Ok(())
            });
        graph.export_texture("wgpu_mip_chain_output", texture);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        let texture_export = execution
            .exports
            .texture_export("wgpu_mip_chain_output")
            .expect("wgpu mip-chain graph-created texture export is promoted");
        assert!(texture_export.promoted);
        assert_eq!(texture_export.dimension, TextureDimension::D2);
        assert_eq!(texture_export.mip_levels, 3);
        assert!(texture_export.has_packed_subresources());
        assert!(texture_export.complete_subresource_coverage);
        let texture_info = renderer.texture_info(texture_export.texture).unwrap();
        assert_eq!(texture_info.mip_levels, 3);
        assert!(texture_info.has_packed_subresources());
        assert_eq!(
            renderer.texture_bytes(texture_export.texture),
            Some(expected.as_slice())
        );
    }

