    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn execute_graph_to_resources_wgpu_resolves_msaa_texture_desc_with_custom_shader() {
        let _wgpu_guard = crate::wgpu_test_serial_guard();
        let mut config = RendererConfig::default();
        config.backend = BackendPreference::Wgpu;
        let mut renderer = match block_on_ready(Renderer::new(config)) {
            Ok(renderer) => renderer,
            Err(error) => {
                eprintln!("skipping wgpu graph-created MSAA custom resolve test: {error}");
                return;
            }
        };
        let mut graph = RenderGraphBuilder::default();
        let source = graph
            .try_create_texture_from_desc(
                "wgpu_custom_resolve_msaa_source",
                TextureDesc {
                    label: Some("wgpu_custom_resolve_msaa_source"),
                    dimension: TextureDimension::D2,
                    width: 2,
                    height: 2,
                    depth_or_layers: 1,
                    mip_levels: 1,
                    samples: 4,
                    format: TextureFormat::Rgba8Unorm,
                    usage: TextureUsage::RENDER_TARGET | TextureUsage::SAMPLED,
                    initial_data: None,
                },
            )
            .unwrap();
        let target = graph
            .try_create_texture_from_desc(
                "wgpu_custom_resolve_msaa_target",
                TextureDesc {
                    label: Some("wgpu_custom_resolve_msaa_target"),
                    dimension: TextureDimension::D2,
                    width: 2,
                    height: 2,
                    depth_or_layers: 1,
                    mip_levels: 1,
                    samples: 1,
                    format: TextureFormat::Rgba8Unorm,
                    usage: TextureUsage::STORAGE | TextureUsage::COPY_SRC,
                    initial_data: None,
                },
            )
            .unwrap();
        graph
            .add_pass("wgpu_write_msaa_source_for_custom_resolve")
            .color_attachment(source, ColorAttachmentOps::clear_store())
            .execute(|_| Ok(()));
        let shader = RhiResolveShaderDesc {
            label: Some("wgpu_custom_msaa_resolve_shader".to_owned()),
            entry_point: "main".to_owned(),
            source: r#"
                @group(0) @binding(0)
                var source_tex: texture_multisampled_2d<f32>;

                @group(0) @binding(1)
                var target_tex: texture_storage_2d<rgba8unorm, write>;

                @compute @workgroup_size(8, 8)
                fn main(@builtin(global_invocation_id) id: vec3<u32>) {
                    let dims = textureDimensions(target_tex);
                    if (id.x >= dims.x || id.y >= dims.y) {
                        return;
                    }
                    let value = textureLoad(
                        source_tex,
                        vec2<i32>(i32(id.x), i32(id.y)),
                        0
                    );
                    textureStore(
                        target_tex,
                        vec2<i32>(i32(id.x), i32(id.y)),
                        value
                    );
                }
            "#.to_owned(),
        };
        let pass_shader = shader;
        graph
            .add_pass("wgpu_custom_resolve_msaa_output")
            .read_texture(source, TextureReadUsage::Sampled)
            .write_texture(target, TextureWriteUsage::Storage)
            .execute(move |ctx| {
                ctx.resolve_rhi_texture_rgba8_with_shader(source, target, &pass_shader)
            });
        graph.export_texture("wgpu_custom_msaa_resolve_output", target);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();

        let texture_export = execution
            .exports
            .texture_export("wgpu_custom_msaa_resolve_output")
            .expect("wgpu MSAA graph-created custom resolved texture export is promoted");
        assert!(texture_export.promoted);
        assert_eq!(texture_export.label, "wgpu_custom_msaa_resolve_output");
        assert_eq!(texture_export.source, RendererGraphExportSource::PromotedTransient);
        assert_eq!(texture_export.dimension, TextureDimension::D2);
        assert_eq!(texture_export.width, 2);
        assert_eq!(texture_export.height, 2);
        assert_eq!(texture_export.depth_or_layers, 1);
        assert_eq!(texture_export.mip_levels, 1);
        assert_eq!(texture_export.samples, 1);
        assert_eq!(texture_export.format, TextureFormat::Rgba8Unorm);
        assert!(texture_export.complete_subresource_coverage);
        assert_eq!(
            texture_export.subresources.len(),
            1,
            "custom resolve output should carry one public subresource"
        );
        let texture_info = renderer.texture_info(texture_export.texture).unwrap();
        assert_eq!(texture_info.dimension, TextureDimension::D2);
        assert_eq!(texture_info.samples, 1);
        assert_eq!(
            texture_info.subresources.len(),
            1,
            "custom resolved transient should materialize as single public subresource"
        );
        let expected_resolved = vec![0; 2 * 2 * 4];
        assert_eq!(
            renderer.texture_bytes(texture_export.texture),
            Some(expected_resolved.as_slice())
        );
    }

    #[test]
    fn execute_graph_to_resources_texture_import_support_reports_msaa_and_flattened_shapes() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let msaa = renderer
            .create_texture(TextureDesc {
                label: Some("support_msaa_import"),
                dimension: TextureDimension::D2,
                width: 2,
                height: 2,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 4,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        let msaa_support = renderer.graph_texture_import_support(msaa).unwrap();
        assert_eq!(msaa_support.texture, msaa);
        assert!(msaa_support.supported);
        assert!(msaa_support.unsupported_reason.is_none());
        assert_eq!(msaa_support.samples, 4);
        assert!(msaa_support.resolved_msaa_compatible);
        assert_eq!(msaa_support.represented_width, 2);
        assert_eq!(msaa_support.represented_height, 2);
        assert_eq!(msaa_support.represented_layer_count, 1);
        assert_eq!(msaa_support.represented_byte_len, 2 * 2 * 4);
        assert!(msaa_support.complete_subresource_coverage);

        let array = renderer
            .create_texture(TextureDesc {
                label: Some("support_array_import"),
                dimension: TextureDimension::D2Array,
                width: 2,
                height: 2,
                depth_or_layers: 2,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        let array_support = renderer.graph_texture_import_support(array).unwrap();
        assert!(array_support.supported);
        assert!(array_support.unsupported_reason.is_none());
        assert_eq!(array_support.dimension, TextureDimension::D2Array);
        assert!(array_support.flattened_rhi_compatible);
        assert_eq!(array_support.represented_mip, 0);
        assert_eq!(array_support.represented_width, 2);
        assert_eq!(array_support.represented_height, 2);
        assert_eq!(array_support.represented_layer_count, 2);
        assert_eq!(array_support.represented_byte_len, 2 * 2 * 2 * 4);
        assert!(array_support.complete_subresource_coverage);

        let mip_texture = renderer
            .create_texture(TextureDesc {
                label: Some("support_non_base_mip_import"),
                dimension: TextureDimension::D2,
                width: 4,
                height: 4,
                depth_or_layers: 1,
                mip_levels: 3,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        let mip_bytes = vec![1_u8; 16];
        renderer
            .update_texture(
                mip_texture,
                TextureUpdate {
                    subresource: TextureSubresource {
                        mip_level: 1,
                        array_layer: 0,
                    },
                    region: TextureRegion {
                        offset: [0, 0, 0],
                        extent: [2, 2, 1],
                    },
                    bytes_per_row: 8,
                    rows_per_image: 2,
                    data: &mip_bytes,
                },
            )
            .unwrap();
        let mip_support = renderer.graph_texture_import_support(mip_texture).unwrap();
        assert!(mip_support.supported);
        assert!(!mip_support.flattened_rhi_compatible);
        assert_eq!(mip_support.represented_mip, 1);
        assert_eq!(mip_support.represented_width, 2);
        assert_eq!(mip_support.represented_height, 2);
        assert_eq!(mip_support.represented_layer_count, 1);
        assert_eq!(mip_support.represented_byte_len, 2 * 2 * 4);
        assert!(!mip_support.complete_mip_coverage);
        assert!(mip_support.complete_layer_coverage);
        assert!(!mip_support.complete_subresource_coverage);

        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("support_public_buffer_import"),
                size: 8,
                usage: BufferUsage::COPY_SRC | BufferUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        let buffer_update = vec![9, 8, 7];
        renderer
            .update_buffer(
                buffer,
                BufferUpdate {
                    byte_offset: 2,
                    data: &buffer_update,
                },
            )
            .unwrap();
        let buffer_support = renderer.graph_buffer_import_support(buffer).unwrap();
        assert_eq!(buffer_support.buffer, buffer);
        assert!(buffer_support.supported);
        assert!(buffer_support.unsupported_reason.is_none());
        assert_eq!(buffer_support.size, 8);
        assert!(buffer_support.usage.contains(BufferUsage::COPY_SRC));
        assert!(buffer_support.usage.contains(BufferUsage::COPY_DST));
        assert_eq!(buffer_support.byte_offset, 2);
        assert_eq!(buffer_support.byte_len, 3);
        assert_eq!(buffer_support.byte_ranges.len(), 1);
        assert_eq!(buffer_support.byte_ranges[0].byte_offset, 2);
        assert_eq!(buffer_support.byte_ranges[0].byte_len, 3);
        assert!(!buffer_support.complete_byte_coverage);

        let mut graph = RenderGraphBuilder::default();
        let imported_msaa = graph.import_texture(
            "support_msaa_graph_import",
            msaa,
            GraphTextureUsage::COPY_SRC,
        );
        let imported_array = graph.import_texture(
            "support_array_graph_import",
            array,
            GraphTextureUsage::COPY_SRC,
        );
        let imported_buffer = graph.import_buffer(
            "support_buffer_graph_import",
            buffer,
            GraphBufferUsage::COPY_SRC,
        );
        graph
            .add_pass("support_query_only")
            .read_texture(imported_msaa, TextureReadUsage::CopySrc)
            .read_texture(imported_array, TextureReadUsage::CopySrc)
            .read_buffer(imported_buffer, BufferReadUsage::CopySrc)
            .execute(|_| Ok(()));
        let graph_support = renderer.graph_import_support(&graph).unwrap();
        assert_eq!(graph_support.textures.len(), 2);
        assert_eq!(graph_support.buffers.len(), 1);
        assert_eq!(graph_support.unsupported_texture_imports(), 0);
        assert_eq!(graph_support.unsupported_buffer_imports(), 0);
        assert_eq!(graph_support.unsupported_imports(), 0);
        assert!(graph_support.all_imports_supported());
        assert_eq!(graph_support.resolved_msaa_texture_imports(), 1);
        assert!(graph_support
            .textures
            .iter()
            .any(|support| support.texture == msaa && support.supported && support.samples == 4));
        assert!(graph_support
            .textures
            .iter()
            .any(|support| support.texture == array && support.flattened_rhi_compatible));
        assert!(graph_support
            .buffers
            .iter()
            .any(|support| support.buffer == buffer
                && support.byte_offset == 2
                && support.byte_len == 3
                && !support.complete_byte_coverage));
    }

    #[test]
    fn execute_graph_to_resources_imports_msaa_textures_as_resolved_payloads() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let initial = (0_u8..16).collect::<Vec<_>>();
        let updated = (32_u8..48).collect::<Vec<_>>();
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("resolved_msaa_import"),
                dimension: TextureDimension::D2,
                width: 2,
                height: 2,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 4,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::COPY_SRC | TextureUsage::COPY_DST,
                initial_data: Some(TextureInitialData {
                    bytes: &initial,
                    bytes_per_row: 8,
                    rows_per_image: 2,
                }),
            })
            .unwrap();
        let mut graph = RenderGraphBuilder::default();
        let imported = graph.import_texture(
            "resolved_msaa_import",
            texture,
            GraphTextureUsage::COPY_SRC | GraphTextureUsage::COPY_DST,
        );
        let pass_initial = initial.clone();
        let pass_updated = updated.clone();
        graph
            .add_pass("rewrite_resolved_msaa_import")
            .read_texture(imported, TextureReadUsage::CopySrc)
            .write_texture(imported, TextureWriteUsage::CopyDst)
            .execute(move |ctx| {
                let rhi_texture = ctx.rhi_texture(imported)?;
                let imported_bytes = ctx.rhi_device()?.read_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                )?;
                if imported_bytes != pass_initial {
                    return Err(RendererError::Validation(
                        "resolved MSAA import did not expose initial resolved bytes".to_owned(),
                    ));
                }
                ctx.rhi_device()?.write_texture_rgba8(
                    rhi_texture,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                    &pass_updated,
                )
            });
        graph.export_texture("resolved_msaa_output", imported);

        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();
        let export = execution
            .exports
            .texture_export("resolved_msaa_output")
            .expect("resolved MSAA import export is tracked");
        assert!(!export.promoted);
        assert_eq!(export.texture, texture);
        assert_eq!(export.samples, 4);
        assert!(export.resolved_msaa_compatible);
        assert_eq!(execution.exports.resolved_msaa_texture_exports(), 1);
        assert_eq!(renderer.texture_bytes(texture), Some(updated.as_slice()));
        let info = renderer.texture_info(texture).unwrap();
        assert_eq!(info.samples, 4);
        assert_eq!(info.subresources.len(), 1);
        assert!(info.complete_subresource_coverage);

        renderer
            .capture_next_frame(CaptureOptions {
                label: Some("resolved_msaa_export_capture".to_owned()),
                backend: FrameCaptureBackend::Internal,
                include_resource_dump: true,
                open_after_capture: false,
            })
            .unwrap();
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("resolved_msaa_export_observability_view".to_owned()),
                scene,
                camera: test_camera(),
                target: RenderTarget::Headless {
                    width: 4,
                    height: 4,
                    format: TextureFormat::Rgba8Unorm,
                },
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings::default(),
                layers: RenderLayerMask::all(),
                graph_extensions: Vec::new(),
            })
            .unwrap();
        let stats = frame.finish().unwrap();
        assert_eq!(stats.public_graph_resolved_msaa_texture_exports, 1);
        assert_eq!(
            stats.public_graph_resolved_msaa_texture_export_labels,
            vec!["resolved_msaa_output".to_owned()]
        );
        assert_eq!(
            stats.public_graph_resolved_msaa_texture_export_label_count(),
            1
        );
        assert!(stats.has_complete_public_graph_export_label_coverage());
        let profile = stats.profile.as_ref().expect("profile is attached");
        assert_eq!(profile.public_graph_resolved_msaa_texture_exports, 1);
        assert_eq!(
            profile.public_graph_resolved_msaa_texture_export_labels,
            vec!["resolved_msaa_output".to_owned()]
        );
        assert_eq!(
            profile.public_graph_resolved_msaa_texture_export_label_count(),
            1
        );
        assert!(profile.has_complete_public_graph_export_label_coverage());
        let report = renderer.frame_debug_report().unwrap();
        assert_eq!(report.public_graph_resolved_msaa_texture_exports, 1);
        assert_eq!(
            report.public_graph_resolved_msaa_texture_export_labels,
            vec!["resolved_msaa_output".to_owned()]
        );
        assert_eq!(
            report.public_graph_resolved_msaa_texture_export_label_count(),
            1
        );
        assert!(report.has_complete_public_graph_export_label_coverage());
        let capture = stats.capture.expect("resolved MSAA capture is attached");
        assert_eq!(capture.public_graph_resolved_msaa_texture_exports, 1);
        assert_eq!(
            capture.public_graph_resolved_msaa_texture_export_labels,
            vec!["resolved_msaa_output".to_owned()]
        );
        assert_eq!(
            capture.public_graph_resolved_msaa_texture_export_label_count(),
            1
        );
        assert!(capture.has_complete_public_graph_export_label_coverage());
        let dump = capture.resource_dump.expect("resource dump is attached");
        assert_eq!(dump.public_graph_resolved_msaa_texture_exports, 1);
        assert_eq!(
            dump.public_graph_resolved_msaa_texture_export_labels,
            vec!["resolved_msaa_output".to_owned()]
        );
        assert!(dump.has_complete_public_graph_export_label_coverage());
    }

