    #[test]
    fn headless_surface_frame_outputs_are_durable_public_textures() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        renderer.resize_surface(8, 4).unwrap();
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();

        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("headless_main_surface_output".to_owned()),
                scene,
                camera: test_camera(),
                target: RenderTarget::MainSurface,
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings::default(),
                layers: RenderLayerMask::all(),
                graph_extensions: Vec::new(),
            })
            .unwrap();
        let stats = frame.finish().unwrap();
        let output = stats
            .public_frame_outputs
            .iter()
            .find(|output| output.view_label.as_deref() == Some("headless_main_surface_output"))
            .expect("headless main surface output is public");
        assert_eq!(
            output.source,
            FramePublicOutputSource::HeadlessMainSurfaceGenerated
        );
        assert_eq!(output.width, 8);
        assert_eq!(output.height, 4);
        assert_eq!(output.format, TextureFormat::Rgba8Unorm);
        assert_eq!(output.base_mip, 0);
        assert_eq!(output.mip_count, 1);
        assert_eq!(output.base_layer, 0);
        assert_eq!(output.layer_count, 1);
        assert_eq!(output.post_process_samples, 0);
        let info = renderer.texture_info(output.color).unwrap();
        assert_eq!(info.width, 8);
        assert_eq!(info.height, 4);
        assert_eq!(
            renderer.texture_bytes(output.color).unwrap().len(),
            8 * 4 * 4
        );

        let surface = make_handle(ResourceKind::Surface, 0, 1);
        renderer.main_surface = Some(surface);
        renderer.surface_extent = Some((6, 3));
        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("headless_surface_handle_output".to_owned()),
                scene,
                camera: test_camera(),
                target: RenderTarget::Surface(surface),
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings::default(),
                layers: RenderLayerMask::all(),
                graph_extensions: Vec::new(),
            })
            .unwrap();
        let stats = frame.finish().unwrap();
        let output = stats
            .public_frame_outputs
            .iter()
            .find(|output| output.view_label.as_deref() == Some("headless_surface_handle_output"))
            .expect("headless surface handle output is public");
        assert_eq!(
            output.source,
            FramePublicOutputSource::HeadlessSurfaceGenerated
        );
        assert_eq!(output.width, 6);
        assert_eq!(output.height, 3);
        assert_eq!(output.format, TextureFormat::Rgba8Unorm);
        let info = renderer.texture_info(output.color).unwrap();
        assert_eq!(info.width, 6);
        assert_eq!(info.height, 3);
        assert_eq!(
            renderer.texture_bytes(output.color).unwrap().len(),
            6 * 3 * 4
        );
    }

    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn backend_surface_readback_materializes_durable_public_frame_output() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let view = ViewDesc {
            label: Some("backend_surface_output".to_owned()),
            scene,
            camera: test_camera(),
            target: RenderTarget::MainSurface,
            render_path: RenderPath::Forward,
            quality: ViewQualitySettings::default(),
            layers: RenderLayerMask::all(),
            graph_extensions: Vec::new(),
        };
        let readback_bytes = vec![1_u8, 2, 3, 255, 4, 5, 6, 255, 7, 8, 9, 255, 10, 11, 12, 255];
        let readback = graphics_wgpu::WgpuFrameReadback {
            width: 2,
            height: 2,
            format: graphics_wgpu::wgpu::TextureFormat::Bgra8UnormSrgb,
            bytes_per_row: 8,
            rows_per_image: 2,
            bytes: readback_bytes.clone(),
        };

        let output = renderer
            .backend_surface_public_frame_output_from_readback(
                &view,
                FramePublicOutputSource::BackendMainSurfaceReadback,
                &readback,
                TextureFormat::Bgra8UnormSrgb,
            )
            .unwrap()
            .expect("backend surface readback is materialized");

        assert_eq!(output.view_label.as_deref(), Some("backend_surface_output"));
        assert_eq!(
            output.source,
            FramePublicOutputSource::BackendMainSurfaceReadback
        );
        assert_eq!(output.content, FramePublicOutputContent::ClearColor);
        assert_eq!(output.width, 2);
        assert_eq!(output.height, 2);
        assert_eq!(output.format, TextureFormat::Bgra8UnormSrgb);
        assert_eq!(output.base_mip, 0);
        assert_eq!(output.mip_count, 1);
        assert_eq!(output.base_layer, 0);
        assert_eq!(output.layer_count, 1);
        assert_eq!(output.subresources.len(), 1);
        assert_eq!(output.subresources[0].byte_len, 16);
        let info = renderer.texture_info(output.color).unwrap();
        assert_eq!(
            info.label.as_deref(),
            Some("backend_surface_output_backend_surface_readback")
        );
        assert_eq!(info.width, 2);
        assert_eq!(info.height, 2);
        assert_eq!(info.format, TextureFormat::Bgra8UnormSrgb);
        assert!(info.usage.contains(TextureUsage::RENDER_TARGET));
        assert!(info.usage.contains(TextureUsage::SAMPLED));
        assert!(info.usage.contains(TextureUsage::COPY_SRC));
        assert_eq!(
            renderer.texture_bytes(output.color),
            Some(readback_bytes.as_slice())
        );
    }

    #[test]
    fn unsupported_public_frame_outputs_propagate_to_debug_report_and_capture() {
        let unsupported = FramePublicFrameOutputUnsupported {
            view_label: Some("backend_surface_missing_readback".to_owned()),
            source: FramePublicOutputSource::BackendMainSurfaceReadback,
            reason: FramePublicOutputUnsupportedReason::BackendSurfaceReadbackUnavailable,
            message: "backend-wgpu surface readback did not produce bytes for this frame"
                .to_owned(),
        };
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        renderer
            .capture_next_frame(CaptureOptions {
                label: Some("unsupported_public_output_capture".to_owned()),
                backend: FrameCaptureBackend::Internal,
                include_resource_dump: false,
                open_after_capture: false,
            })
            .unwrap();
        let mut stats = FrameStats {
            unsupported_public_frame_outputs: vec![unsupported.clone()],
            ..FrameStats::default()
        };
        renderer.apply_frame_instrumentation(&mut stats);

        assert_eq!(stats.unsupported_public_frame_output_count(), 1);
        let report = FrameDebugReport::from_stats(&stats);
        assert_eq!(
            report.unsupported_public_frame_outputs,
            vec![unsupported.clone()]
        );
        assert_eq!(report.unsupported_public_frame_output_count(), 1);
        let capture = stats.capture.expect("capture is attached");
        assert_eq!(capture.unsupported_public_frame_outputs, vec![unsupported]);
        assert_eq!(capture.unsupported_public_frame_output_count(), 1);
    }

    #[test]
    fn surface_frame_readback_api_requires_backend_surface_renderer() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());

        assert!(!renderer.surface_frame_readback_supported());
        assert!(!renderer.surface_frame_readback_enabled());
        assert!(!renderer.surface_frame_readback_pending());
        assert!(!renderer.surface_frame_readback_available());
        assert!(matches!(
            renderer.set_surface_frame_readback_enabled(true),
            Err(RendererError::Validation(message))
                if message.contains("surface frame readback requires a backend-wgpu surface renderer")
        ));
        assert!(matches!(
            renderer.poll_surface_frame_readback(),
            Err(RendererError::Validation(message))
                if message.contains("surface frame readback requires a backend-wgpu surface renderer")
        ));
        assert!(matches!(
            renderer.materialize_surface_frame_readback(Some("no_surface_readback")),
            Err(RendererError::Validation(message))
                if message.contains("surface frame readback requires a backend-wgpu surface renderer")
        ));
        renderer.request_surface_frame_readback_next_frame();
        assert!(matches!(
            renderer.begin_frame(FrameInput::default()),
            Err(RendererError::Validation(message))
                if message.contains("surface frame readback requires a backend-wgpu surface renderer")
        ));
        renderer
            .begin_frame(FrameInput::default())
            .unwrap()
            .finish()
            .unwrap();
    }

