    #[test]
    fn render_graph_support_surface_export_limitations_stay_in_sync() {
        let renderer = Renderer::new_headless(RendererConfig::default());
        let surface_support = renderer.surface_graph_export_support();
        let render_support = renderer.render_graph_support();
        let direct = render_support
            .support_for(RendererGraphCapability::DirectSwapchainGraphExport)
            .expect("direct swapchain graph export capability is always present in support matrix");

        assert_eq!(
            direct.limitation,
            surface_support.unsupported_reason.as_deref(),
            "direct swapchain capability limitation should reuse surface export gate message"
        );
        assert_eq!(
            direct.supported,
            surface_support.direct_swapchain_export_supported
        );
        assert!(!direct.supported);
        assert_eq!(direct.level, RendererGraphCapabilityLevel::CapabilityGated);
    }

    #[test]
    fn texture_frame_outputs_write_clear_color_to_existing_public_texture() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let initial = vec![0_u8; 16];
        let target = renderer
            .create_texture(TextureDesc {
                label: Some("existing_public_frame_target"),
                dimension: TextureDimension::D2,
                width: 2,
                height: 2,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8Unorm,
                usage: TextureUsage::RENDER_TARGET | TextureUsage::SAMPLED | TextureUsage::COPY_SRC,
                initial_data: Some(TextureInitialData {
                    bytes: &initial,
                    bytes_per_row: 8,
                    rows_per_image: 2,
                }),
            })
            .unwrap();
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let mut camera = test_camera();
        camera.clear = ClearOptions::ColorDepth(Color::rgba(0.1, 0.2, 0.3, 1.0));
        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("existing_public_frame_view".to_owned()),
                scene,
                camera,
                target: RenderTarget::Texture(target),
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings::default(),
                layers: RenderLayerMask::all(),
                graph_extensions: Vec::new(),
            })
            .unwrap();
        let stats = frame.finish().unwrap();

        assert_eq!(stats.public_frame_outputs.len(), 1);
        let output = &stats.public_frame_outputs[0];
        assert_eq!(
            output.source,
            FramePublicOutputSource::ExistingTargetTexture
        );
        assert_eq!(output.content, FramePublicOutputContent::ClearColor);
        assert_eq!(output.color, target);
        assert_eq!(output.width, 2);
        assert_eq!(output.height, 2);
        assert_eq!(output.format, TextureFormat::Rgba8Unorm);
        assert_eq!(output.base_mip, 0);
        assert_eq!(output.mip_count, 1);
        assert_eq!(output.base_layer, 0);
        assert_eq!(output.layer_count, 1);
        assert_eq!(output.visible_geometry, 0);
        assert_eq!(output.material_samples, 0);
        assert_eq!(output.light_samples, 0);
        assert_eq!(output.environment_samples, 0);
        assert_eq!(output.post_process_samples, 0);
        assert_eq!(
            renderer.texture_bytes(target).map(|bytes| &bytes[0..4]),
            Some([26, 51, 77, 255].as_slice())
        );
    }

