    #[test]
    fn destroying_public_graph_export_handles_clears_last_graph_execution() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let mut graph = RenderGraphBuilder::default();
        let texture = graph.create_texture(GraphTextureDesc {
            label: Some("destroy_clear_graph_texture".to_owned()),
            width: 2,
            height: 2,
            format: TextureFormat::Rgba8Unorm,
        });
        let buffer = graph.create_buffer(GraphBufferDesc {
            label: Some("destroy_clear_graph_buffer".to_owned()),
            size: 4,
        });
        let texture_bytes = vec![1, 1, 1, 255, 2, 2, 2, 255, 3, 3, 3, 255, 4, 4, 4, 255];
        let buffer_bytes = vec![5, 6, 7, 8];
        let pass_texture_bytes = texture_bytes.clone();
        let pass_buffer_bytes = buffer_bytes.clone();
        graph
            .add_pass("write_destroy_clear_exports")
            .write_texture(texture, TextureWriteUsage::CopyDst)
            .write_buffer(buffer, BufferWriteUsage::CopyDst)
            .execute(move |ctx| {
                ctx.rhi_device()?.write_texture_rgba8(
                    ctx.rhi_texture(texture)?,
                    RhiTextureRegion {
                        x: 0,
                        y: 0,
                        width: 2,
                        height: 2,
                    },
                    &pass_texture_bytes,
                )?;
                ctx.rhi_device()?
                    .write_buffer(ctx.rhi_buffer(buffer)?, 0, &pass_buffer_bytes)?;
                Ok(())
            });
        graph.export_texture("destroy_clear_texture_output", texture);
        graph.export_buffer("destroy_clear_buffer_output", buffer);
        let execution = renderer.execute_graph_to_resources(&mut graph).unwrap();
        let exported_texture = execution
            .exports
            .texture("destroy_clear_texture_output")
            .unwrap();
        let exported_buffer = execution
            .exports
            .buffer("destroy_clear_buffer_output")
            .unwrap();

        assert!(renderer.last_graph_execution().is_some());
        renderer.destroy(exported_buffer).unwrap();
        assert!(renderer.last_graph_execution().is_none());

        let mut graph = RenderGraphBuilder::default();
        let buffer = graph.create_buffer(GraphBufferDesc {
            label: Some("destroy_clear_second_buffer".to_owned()),
            size: 4,
        });
        graph
            .add_pass("write_destroy_clear_second")
            .write_buffer(buffer, BufferWriteUsage::CopyDst)
            .execute(move |ctx| {
                ctx.rhi_device()?
                    .write_buffer(ctx.rhi_buffer(buffer)?, 0, &[9, 10, 11, 12])?;
                Ok(())
            });
        graph.export_buffer("destroy_clear_second_output", buffer);
        renderer.execute_graph_to_resources(&mut graph).unwrap();
        assert!(renderer.last_graph_execution().is_some());

        renderer.destroy(exported_texture).unwrap();
        assert!(
            renderer.last_graph_execution().is_some(),
            "destroying an older export handle must not clear the latest graph execution"
        );
    }

    #[test]
    fn profiled_render_graph_extension_exports_remain_visible_in_frame_outputs() {
        struct ExportProfiledTextureExtension;

        impl RenderGraphExtension for ExportProfiledTextureExtension {
            fn name(&self) -> &str {
                "export_profiled_texture"
            }

            fn build(
                &self,
                _ctx: &RenderGraphExtensionContext,
                graph: &mut RenderGraphBuilder<'_>,
            ) -> Result<(), RendererError> {
                let texture = graph.create_texture(GraphTextureDesc {
                    label: Some("profiled_export_texture".to_owned()),
                    width: 4,
                    height: 4,
                    format: TextureFormat::Rgba8Unorm,
                });
                graph
                    .add_pass("profiled_export_pass")
                    .write_texture(texture, TextureWriteUsage::Storage)
                    .execute(move |ctx| {
                        ctx.rhi_texture(texture)?;
                        Ok(())
                    });
                graph.export_texture("profiled_texture_output", texture);
                Ok(())
            }
        }

        let mut renderer = Renderer::new_headless(RendererConfig {
            gpu_profiling: true,
            ..RendererConfig::default()
        });
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let mesh = test_mesh(&mut renderer, 0.0);
        let material = test_standard_material(&mut renderer);
        renderer
            .edit_scene(scene, |scene| {
                scene.spawn(RenderObjectDesc {
                    mesh,
                    materials: vec![material],
                    ..RenderObjectDesc::default()
                });
            })
            .unwrap();
        let extension = renderer
            .register_graph_extension(ExportProfiledTextureExtension)
            .unwrap();
        renderer
            .capture_next_frame(CaptureOptions {
                label: Some("profiled_export_capture".to_owned()),
                backend: FrameCaptureBackend::Internal,
                include_resource_dump: false,
                open_after_capture: false,
            })
            .unwrap();

        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("profiled_export_view".to_owned()),
                scene,
                camera: test_camera(),
                target: RenderTarget::Headless {
                    width: 16,
                    height: 16,
                    format: TextureFormat::Rgba8Unorm,
                },
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings::default(),
                layers: RenderLayerMask::all(),
                graph_extensions: vec![extension],
            })
            .unwrap();
        let stats = frame.finish().unwrap();

        assert_eq!(stats.graph.exported_textures, 1);
        assert_eq!(
            stats.graph.exported_texture_labels,
            vec!["profiled_texture_output".to_owned()]
        );
        assert!(stats.gpu_profiler_enabled);
        assert!(stats.gpu_time_ms.is_some());
        let report = renderer.frame_debug_report().unwrap();
        assert_eq!(
            report.graph.exported_texture_labels,
            stats.graph.exported_texture_labels
        );
        let capture = stats.capture.expect("capture is attached");
        assert_eq!(
            capture.graph.exported_texture_labels,
            stats.graph.exported_texture_labels
        );
    }

    #[test]
    fn render_graph_extension_rejects_duplicate_export_labels_through_facade() {
        struct DuplicateExportLabelsExtension;

        impl RenderGraphExtension for DuplicateExportLabelsExtension {
            fn name(&self) -> &str {
                "duplicate_export_labels"
            }

            fn build(
                &self,
                _ctx: &RenderGraphExtensionContext,
                graph: &mut RenderGraphBuilder<'_>,
            ) -> Result<(), RendererError> {
                let texture = graph.create_texture(GraphTextureDesc {
                    label: Some("duplicate_export_texture".to_owned()),
                    width: 4,
                    height: 4,
                    format: TextureFormat::Rgba8Unorm,
                });
                let buffer = graph.create_buffer(GraphBufferDesc {
                    label: Some("duplicate_export_buffer".to_owned()),
                    size: 4,
                });
                graph
                    .add_pass("duplicate_export_pass")
                    .write_texture(texture, TextureWriteUsage::Storage)
                    .write_buffer(buffer, BufferWriteUsage::Storage)
                    .execute(|_| Ok(()));
                graph.export_texture("duplicate_output", texture);
                graph.export_buffer("duplicate_output", buffer);
                Ok(())
            }
        }

        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let mesh = test_mesh(&mut renderer, 0.0);
        let material = test_standard_material(&mut renderer);
        renderer
            .edit_scene(scene, |scene| {
                scene.spawn(RenderObjectDesc {
                    mesh,
                    materials: vec![material],
                    ..RenderObjectDesc::default()
                });
            })
            .unwrap();
        let extension = renderer
            .register_graph_extension(DuplicateExportLabelsExtension)
            .unwrap();

        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        let err = match frame.render_view(ViewDesc {
            label: Some("duplicate_export_view".to_owned()),
            scene,
            camera: test_camera(),
            target: RenderTarget::Headless {
                width: 16,
                height: 16,
                format: TextureFormat::Rgba8Unorm,
            },
            render_path: RenderPath::Forward,
            quality: ViewQualitySettings::default(),
            layers: RenderLayerMask::all(),
            graph_extensions: vec![extension],
        }) {
            Ok(_) => frame.finish().unwrap_err(),
            Err(err) => err,
        };

        assert!(matches!(err, RendererError::RenderGraphValidation(_)));
    }

    #[test]
    fn profiler_populates_gpu_time_for_imported_extension_buffers() {
        struct ImportUniformBufferExtension {
            buffer: BufferHandle,
        }

        impl RenderGraphExtension for ImportUniformBufferExtension {
            fn name(&self) -> &str {
                "import_uniform_buffer"
            }

            fn build(
                &self,
                _ctx: &RenderGraphExtensionContext,
                graph: &mut RenderGraphBuilder<'_>,
            ) -> Result<(), RendererError> {
                let imported = graph.import_buffer(
                    "profiled_uniform_buffer",
                    self.buffer,
                    GraphBufferUsage::UNIFORM,
                );
                graph
                    .add_pass("read_profiled_uniform_buffer")
                    .read_buffer(imported, BufferReadUsage::Uniform)
                    .execute(|_| Ok(()));
                Ok(())
            }
        }

        let mut renderer = Renderer::new_headless(RendererConfig {
            gpu_profiling: true,
            ..RendererConfig::default()
        });
        let scene = renderer.create_scene(SceneDesc::default()).unwrap();
        let mesh = test_mesh(&mut renderer, 0.0);
        let material = test_standard_material(&mut renderer);
        renderer
            .edit_scene(scene, |scene| {
                scene.spawn(RenderObjectDesc {
                    mesh,
                    materials: vec![material],
                    ..RenderObjectDesc::default()
                });
            })
            .unwrap();
        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("profiled_uniform_buffer"),
                size: 16,
                usage: BufferUsage::UNIFORM,
                initial_data: None,
            })
            .unwrap();
        let extension = renderer
            .register_graph_extension(ImportUniformBufferExtension { buffer })
            .unwrap();
        let mut frame = renderer.begin_frame(FrameInput::default()).unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("profiled_import_buffer_view".to_owned()),
                scene,
                camera: test_camera(),
                target: RenderTarget::Headless {
                    width: 16,
                    height: 16,
                    format: TextureFormat::Rgba8Unorm,
                },
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings::default(),
                layers: RenderLayerMask::all(),
                graph_extensions: vec![extension],
            })
            .unwrap();
        let stats = frame.finish().unwrap();
        assert!(stats.gpu_profiler_enabled);
        assert!(stats.graph.timestamp_writes > 0);
        assert!(stats.graph.gpu_time_ns.is_some());
        assert!(stats.gpu_time_ms.is_some_and(|time_ms| time_ms >= 0.0));
        assert_eq!(
            stats
                .profile
                .as_ref()
                .expect("profile data is attached")
                .gpu_time_ms,
            stats.gpu_time_ms
        );
    }

