    #[test]
    fn wait_for_gpu_reclaims_destroy_queued_resources_without_frame_latency() {
        let mut renderer = Renderer::new_headless(RendererConfig {
            frame_latency: 4,
            ..RendererConfig::default()
        });
        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("waited-buffer"),
                size: 16,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: Some(&[1, 2, 3, 4]),
            })
            .unwrap();

        renderer.destroy(buffer).unwrap();
        let queued_destroy_bytes = renderer.memory_stats().delayed_destroy_bytes;
        assert_eq!(renderer.memory_stats().delayed_destroy_count, 1);
        assert_eq!(
            renderer.memory_stats().reclaim_policy,
            ResourceReclaimPolicy::FrameLatency { frames: 4 }
        );

        let stats = renderer
            .begin_frame(FrameInput {
                frame_index_override: Some(0),
                wait_for_gpu: true,
                ..FrameInput::default()
            })
            .unwrap()
            .finish()
            .unwrap();

        assert_eq!(
            stats.memory.reclaim_policy,
            ResourceReclaimPolicy::BackendFence
        );
        assert_eq!(stats.memory.delayed_destroy_count, 0);
        assert_eq!(stats.memory.delayed_destroy_bytes, 0);
        assert_eq!(stats.memory.reclaimed_this_frame, 1);
        assert_eq!(
            stats.memory.reclaimed_bytes_this_frame,
            queued_destroy_bytes
        );
        assert_eq!(renderer.memory_stats().delayed_destroy_count, 0);
        assert_eq!(
            renderer.memory_stats().reclaim_policy,
            ResourceReclaimPolicy::BackendFence
        );
        assert_eq!(renderer.resource_status(buffer), None);
        assert_eq!(stats.upload.bytes_uploaded_this_frame, 4);
        assert_eq!(stats.upload.uploads_completed_this_frame, 1);
        assert_eq!(stats.upload.staging_bytes_released_this_frame, 4);

        let stats = renderer
            .begin_frame(FrameInput {
                frame_index_override: Some(1),
                ..FrameInput::default()
            })
            .unwrap()
            .finish()
            .unwrap();

        assert_eq!(
            stats.memory.reclaim_policy,
            ResourceReclaimPolicy::FrameLatency { frames: 4 }
        );
        assert_eq!(stats.memory.reclaimed_this_frame, 0);
        assert_eq!(stats.memory.reclaimed_bytes_this_frame, 0);
    }

    #[test]
    fn submitted_frame_reclaims_destroy_queued_resources_at_completed_submission_boundary() {
        let mut renderer = Renderer::new_headless(RendererConfig {
            frame_latency: 4,
            ..RendererConfig::default()
        });
        let buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("submitted-boundary-reclaim-buffer"),
                size: 16,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: Some(&[1, 2, 3, 4]),
            })
            .unwrap();
        let mesh = test_mesh(&mut renderer, 0.0);
        let scene = renderer
            .create_scene(SceneDesc {
                label: Some("submitted_boundary_reclaim_scene".to_owned()),
                max_objects_hint: None,
                max_lights_hint: None,
                enable_gpu_culling: false,
                enable_occlusion_culling: false,
            })
            .unwrap();
        renderer
            .edit_scene(scene, |scene| {
                scene.spawn(RenderObjectDesc {
                    mesh,
                    ..RenderObjectDesc::default()
                });
            })
            .unwrap();

        renderer.destroy(buffer).unwrap();
        let queued_destroy_bytes = renderer.memory_stats().delayed_destroy_bytes;
        assert_eq!(renderer.memory_stats().delayed_destroy_count, 1);

        let idle_stats = renderer
            .begin_frame(FrameInput {
                frame_index_override: Some(0),
                ..FrameInput::default()
            })
            .unwrap()
            .finish()
            .unwrap();
        assert_eq!(
            idle_stats.memory.reclaim_policy,
            ResourceReclaimPolicy::FrameLatency { frames: 4 }
        );
        assert_eq!(idle_stats.memory.delayed_destroy_count, 1);
        assert_eq!(idle_stats.memory.reclaimed_this_frame, 0);
        assert_eq!(
            renderer.resource_status(buffer),
            Some(ResourceStatus::DestroyQueued)
        );

        let mut frame = renderer
            .begin_frame(FrameInput {
                frame_index_override: Some(1),
                ..FrameInput::default()
            })
            .unwrap();
        frame
            .render_view(ViewDesc {
                label: Some("submitted_boundary_reclaim_view".to_owned()),
                scene,
                camera: CameraDesc {
                    label: None,
                    transform: IDENTITY_MAT4,
                    projection: Projection::Orthographic {
                        width: 4.0,
                        height: 4.0,
                        near: -10.0,
                        far: 10.0,
                        reverse_z: false,
                    },
                    exposure: Exposure::Auto,
                    clear: ClearOptions::ColorDepth(Color::BLACK),
                    viewport: None,
                    scissor: None,
                    jitter: None,
                    previous_view_proj: None,
                    flags: CameraFlags::MAIN,
                },
                target: RenderTarget::MainSurface,
                render_path: RenderPath::Forward,
                quality: ViewQualitySettings {
                    hdr: false,
                    bloom: false,
                    taa: false,
                    fxaa: false,
                    ssao: false,
                    ssr: false,
                    depth_of_field: false,
                    motion_blur: false,
                    variable_rate_shading: false,
                    bindless_textures: false,
                    mesh_shaders: false,
                    virtual_texturing: false,
                    ray_tracing: false,
                    color_grading: ColorGradingMode::None,
                },
                layers: RenderLayerMask::all(),
                graph_extensions: Vec::new(),
            })
            .unwrap();
        let stats = frame.finish().unwrap();

        assert_eq!(
            stats.memory.reclaim_policy,
            ResourceReclaimPolicy::SubmissionBoundary
        );
        assert_eq!(stats.retired_submission_frame, Some(1));
        assert_eq!(stats.pending_submission_frame, None);
        assert_eq!(stats.memory.delayed_destroy_count, 0);
        assert_eq!(stats.memory.delayed_destroy_bytes, 0);
        assert_eq!(stats.memory.reclaimed_this_frame, 1);
        assert_eq!(
            stats.memory.reclaimed_bytes_this_frame,
            queued_destroy_bytes
        );
        assert_eq!(renderer.memory_stats().delayed_destroy_count, 0);
        assert_eq!(renderer.resource_status(buffer), None);
    }

    #[test]
    fn poll_resource_retirements_completes_only_prior_submission_work() {
        let mut renderer = Renderer::new_headless(RendererConfig {
            frame_latency: 4,
            ..RendererConfig::default()
        });
        let old_buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("poll-old-buffer"),
                size: 16,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        renderer.destroy(old_buffer).unwrap();
        let _submitted_upload = renderer
            .create_buffer(BufferDesc {
                label: Some("poll-submitted-upload"),
                size: 16,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: Some(&[1, 2, 3, 4]),
            })
            .unwrap();
        let submitted_upload_bytes = renderer.upload_stats().bytes_queued;
        let submitted_upload_count = renderer.upload_stats().pending_uploads;
        assert!(submitted_upload_bytes > 0);
        assert!(submitted_upload_count > 0);

        renderer.record_submitted_work_for_retirement(0, true);
        assert_eq!(renderer.pending_submission_boundary_frame, Some(0));
        renderer.frame_index = 1;

        let future_buffer = renderer
            .create_buffer(BufferDesc {
                label: Some("poll-future-buffer"),
                size: 16,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: None,
            })
            .unwrap();
        renderer.destroy(future_buffer).unwrap();
        let _future_upload = renderer
            .create_buffer(BufferDesc {
                label: Some("poll-future-upload"),
                size: 16,
                usage: BufferUsage::STORAGE | BufferUsage::COPY_DST,
                initial_data: Some(&[5, 6]),
            })
            .unwrap();
        let total_upload_bytes = renderer.upload_stats().bytes_queued;
        assert!(total_upload_bytes > submitted_upload_bytes);

        let poll = renderer.poll_resource_retirements();
        assert!(poll.submission_complete);
        assert_eq!(poll.retired_submission_frame, Some(0));
        assert_eq!(poll.pending_submission_frame, None);
        assert_eq!(
            poll.memory.reclaim_policy,
            ResourceReclaimPolicy::SubmissionBoundary
        );
        assert_eq!(poll.memory.reclaimed_this_frame, 1);
        assert_eq!(
            poll.upload.bytes_uploaded_this_frame,
            submitted_upload_bytes
        );
        assert_eq!(
            poll.upload.uploads_completed_this_frame,
            submitted_upload_count
        );
        assert_eq!(
            poll.upload.bytes_queued,
            total_upload_bytes.saturating_sub(submitted_upload_bytes)
        );
        assert_eq!(poll.upload.pending_uploads, 1);
        assert_eq!(renderer.resource_status(old_buffer), None);
        assert_eq!(
            renderer.resource_status(future_buffer),
            Some(ResourceStatus::DestroyQueued)
        );

        let second_poll = renderer.poll_resource_retirements();
        assert_eq!(second_poll.retired_submission_frame, None);
        assert_eq!(
            second_poll.memory.reclaim_policy,
            ResourceReclaimPolicy::FrameLatency { frames: 4 }
        );
        assert_eq!(second_poll.memory.reclaimed_this_frame, 0);
        assert_eq!(second_poll.upload.bytes_uploaded_this_frame, 0);
        assert_eq!(second_poll.upload.uploads_completed_this_frame, 0);
        assert_eq!(second_poll.upload.bytes_queued, poll.upload.bytes_queued);
        assert_eq!(
            renderer.resource_status(future_buffer),
            Some(ResourceStatus::DestroyQueued)
        );
    }

    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn renderer_backend_retirement_stats_map_post_pass_buffers() {
        let mapped: BackendResourceRetirementStats =
            backend_wgpu::WgpuBackendResourceRetirementStats {
                post_pass_vertex_buffers: 2,
                post_pass_index_buffers: 1,
                fence_submission_indices: 4,
                fence_objects_without_submission_index: 5,
                retired_post_pass_vertex_buffers_this_poll: 3,
                retired_post_pass_index_buffers_this_poll: 2,
                retired_fence_submission_indices_this_poll: 6,
                retired_fence_objects_without_submission_index_this_poll: 7,
                last_poll_queue_empty: true,
                retired_after_queue_empty_poll: true,
                last_poll_completed_submission_index_recorded: true,
                retired_after_completed_submission_index_poll: true,
                nonblocking_submission_index_poll_supported: false,
                queue_empty_poll_fallback: true,
                last_poll_used_queue_empty_fallback: true,
                tombstones_with_submission_index: 8,
                tombstones_without_submission_index: 9,
                tombstones_waiting_for_submission_index: 12,
                tombstones_waiting_for_queue_empty: 13,
                tombstone_submission_index_coverage:
                    backend_wgpu::WgpuTombstoneSubmissionIndexCoverage::Partial,
                all_tombstones_have_submission_index: true,
                partial_tombstone_submission_index_coverage: true,
                no_tombstones_have_submission_index: true,
                retired_tombstones_with_submission_index_this_poll: 10,
                retired_tombstones_without_submission_index_this_poll: 11,
                retired_tombstone_submission_index_coverage_this_poll:
                    backend_wgpu::WgpuTombstoneSubmissionIndexCoverage::All,
                retired_all_tombstones_had_submission_index_this_poll: true,
                retired_partial_tombstone_submission_index_coverage_this_poll: true,
                retired_no_tombstones_had_submission_index_this_poll: true,
                ..Default::default()
            }
            .into();

        assert!(mapped.last_poll_queue_empty);
        assert!(mapped.retired_after_queue_empty_poll);
        assert!(mapped.last_poll_completed_submission_index_recorded);
        assert!(mapped.retired_after_completed_submission_index_poll);
        assert!(!mapped.nonblocking_submission_index_poll_supported);
        assert!(mapped.queue_empty_poll_fallback);
        assert!(mapped.last_poll_used_queue_empty_fallback);
        assert_eq!(mapped.tombstones_with_submission_index, 8);
        assert_eq!(mapped.tombstones_without_submission_index, 9);
        assert_eq!(mapped.tombstones_waiting_for_submission_index, 12);
        assert_eq!(mapped.tombstones_waiting_for_queue_empty, 13);
        assert_eq!(
            mapped.tombstone_submission_index_coverage,
            TombstoneSubmissionIndexCoverage::Partial
        );
        assert!(mapped.all_tombstones_have_submission_index);
        assert!(mapped.partial_tombstone_submission_index_coverage);
        assert!(mapped.no_tombstones_have_submission_index);
        assert_eq!(
            mapped.retired_tombstones_with_submission_index_this_poll,
            10
        );
        assert_eq!(
            mapped.retired_tombstones_without_submission_index_this_poll,
            11
        );
        assert_eq!(
            mapped.retired_tombstone_submission_index_coverage_this_poll,
            TombstoneSubmissionIndexCoverage::All
        );
        assert!(mapped.retired_all_tombstones_had_submission_index_this_poll);
        assert!(mapped.retired_partial_tombstone_submission_index_coverage_this_poll);
        assert!(mapped.retired_no_tombstones_had_submission_index_this_poll);
        assert_eq!(mapped.post_pass_vertex_buffers, 2);
        assert_eq!(mapped.post_pass_index_buffers, 1);
        assert_eq!(mapped.fence_submission_indices, 4);
        assert_eq!(mapped.fence_objects_without_submission_index, 5);
        assert_eq!(mapped.retired_post_pass_vertex_buffers_this_poll, 3);
        assert_eq!(mapped.retired_post_pass_index_buffers_this_poll, 2);
        assert_eq!(mapped.retired_fence_submission_indices_this_poll, 6);
        assert_eq!(
            mapped.retired_fence_objects_without_submission_index_this_poll,
            7
        );
    }

    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn renderer_memory_stats_expose_backend_tombstone_retirement() {
        let mut renderer = match Renderer::new_wgpu(RendererConfig::default()) {
            Ok(renderer) => renderer,
            Err(error) => {
                eprintln!("skipping renderer backend tombstone memory stats test: {error}");
                return;
            }
        };
        let shader = ShaderHandle::from_raw(std::num::NonZeroU64::new(801).unwrap());
        let source = ShaderSource::Wgsl(
            r#"
            @fragment
            fn fs_main() -> @location(0) vec4<f32> {
                return vec4<f32>(1.0, 0.0, 0.0, 1.0);
            }
            "#,
        );
        let flags = vec!["backend-tombstone".to_owned()];
        let runtime = renderer
            .wgpu_runtime
            .as_mut()
            .expect("new_wgpu creates a wgpu runtime");
        runtime
            .compile_and_cache_shader_variant_module(shader, &flags, &source, Some("variant"))
            .unwrap();
        assert_eq!(
            runtime.invalidate_shader_variant_modules_for_shader(shader),
            1
        );

        let memory = renderer.memory_stats();
        assert_eq!(memory.backend_retirement.tombstones, 1);
        assert_eq!(memory.backend_retirement.fence_objects, 1);
        assert_eq!(memory.backend_retirement.fence_submission_indices, 0);
        assert_eq!(
            memory
                .backend_retirement
                .fence_objects_without_submission_index,
            1
        );
        assert_eq!(
            memory.backend_retirement.tombstones_with_submission_index,
            0
        );
        assert!(
            !memory
                .backend_retirement
                .nonblocking_submission_index_poll_supported
        );
        assert!(memory.backend_retirement.queue_empty_poll_fallback);
        assert!(
            !memory
                .backend_retirement
                .last_poll_used_queue_empty_fallback
        );
        assert_eq!(
            memory
                .backend_retirement
                .tombstones_without_submission_index,
            1
        );
        assert_eq!(
            memory
                .backend_retirement
                .tombstones_waiting_for_submission_index,
            0
        );
        assert_eq!(
            memory.backend_retirement.tombstones_waiting_for_queue_empty,
            1
        );
        assert_eq!(
            memory
                .backend_retirement
                .tombstone_submission_index_coverage,
            TombstoneSubmissionIndexCoverage::None
        );
        assert!(
            !memory
                .backend_retirement
                .all_tombstones_have_submission_index
        );
        assert!(
            memory
                .backend_retirement
                .no_tombstones_have_submission_index
        );
        assert_eq!(memory.backend_retirement.shader_variant_modules, 1);
        assert_eq!(
            memory
                .backend_retirement
                .retired_shader_variant_modules_this_poll,
            0
        );
        let dump = renderer.frame_capture_resource_dump();
        assert_eq!(dump.backend_retirement, memory.backend_retirement);

        let poll = renderer.poll_resource_retirements();
        assert_eq!(poll.memory.backend_retirement.tombstones, 0);
        assert!(poll.memory.backend_retirement.last_poll_queue_empty);
        assert!(
            poll.memory
                .backend_retirement
                .last_poll_used_queue_empty_fallback
        );
        assert!(
            poll.memory
                .backend_retirement
                .retired_after_queue_empty_poll
        );
        assert!(
            !poll
                .memory
                .backend_retirement
                .last_poll_completed_submission_index_recorded
        );
        assert!(
            !poll
                .memory
                .backend_retirement
                .retired_after_completed_submission_index_poll
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_shader_variant_modules_this_poll,
            1
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_fence_objects_this_poll,
            1
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_fence_submission_indices_this_poll,
            0
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_fence_objects_without_submission_index_this_poll,
            1
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_tombstones_with_submission_index_this_poll,
            0
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_tombstones_without_submission_index_this_poll,
            1
        );
        assert_eq!(
            poll.memory
                .backend_retirement
                .retired_tombstone_submission_index_coverage_this_poll,
            TombstoneSubmissionIndexCoverage::None
        );
        assert!(
            !poll
                .memory
                .backend_retirement
                .retired_all_tombstones_had_submission_index_this_poll
        );
        assert!(
            poll.memory
                .backend_retirement
                .retired_no_tombstones_had_submission_index_this_poll
        );
        let final_memory = renderer.memory_stats();
        assert_eq!(final_memory.backend_retirement.tombstones, 0);
        assert_eq!(
            final_memory
                .backend_retirement
                .tombstones_waiting_for_submission_index,
            0
        );
        assert_eq!(
            final_memory
                .backend_retirement
                .tombstones_waiting_for_queue_empty,
            0
        );
        assert_eq!(
            final_memory
                .backend_retirement
                .tombstone_submission_index_coverage,
            TombstoneSubmissionIndexCoverage::NotApplicable
        );

        let idle_poll = renderer.poll_resource_retirements();
        assert_eq!(
            idle_poll
                .memory
                .backend_retirement
                .retired_tombstone_submission_index_coverage_this_poll,
            TombstoneSubmissionIndexCoverage::NotApplicable
        );
        assert!(
            !idle_poll
                .memory
                .backend_retirement
                .retired_after_queue_empty_poll
        );
    }

    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn begin_frame_automatically_polls_backend_tombstone_retirement() {
        let mut renderer = match Renderer::new_wgpu(RendererConfig::default()) {
            Ok(renderer) => renderer,
            Err(error) => {
                eprintln!("skipping renderer backend tombstone auto poll test: {error}");
                return;
            }
        };
        let shader = ShaderHandle::from_raw(std::num::NonZeroU64::new(802).unwrap());
        let source = ShaderSource::Wgsl(
            r#"
            @fragment
            fn fs_main() -> @location(0) vec4<f32> {
                return vec4<f32>(0.0, 0.0, 1.0, 1.0);
            }
            "#,
        );
        let flags = vec!["backend-auto-retire".to_owned()];
        let runtime = renderer
            .wgpu_runtime
            .as_mut()
            .expect("new_wgpu creates a wgpu runtime");
        runtime
            .compile_and_cache_shader_variant_module(shader, &flags, &source, Some("variant"))
            .unwrap();
        assert_eq!(
            runtime.invalidate_shader_variant_modules_for_shader(shader),
            1
        );
        assert_eq!(renderer.memory_stats().backend_retirement.tombstones, 1);
        assert_eq!(
            renderer
                .memory_stats()
                .backend_retirement
                .fence_submission_indices,
            0
        );
        assert_eq!(
            renderer
                .memory_stats()
                .backend_retirement
                .fence_objects_without_submission_index,
            1
        );
        assert!(
            !renderer
                .memory_stats()
                .backend_retirement
                .all_tombstones_have_submission_index
        );
        assert!(
            renderer
                .memory_stats()
                .backend_retirement
                .no_tombstones_have_submission_index
        );
        assert_eq!(
            renderer
                .memory_stats()
                .backend_retirement
                .tombstone_submission_index_coverage,
            TombstoneSubmissionIndexCoverage::None
        );
        renderer
            .capture_next_frame(CaptureOptions {
                label: Some("backend_tombstone_auto".to_owned()),
                backend: FrameCaptureBackend::Internal,
                include_resource_dump: true,
                open_after_capture: false,
            })
            .unwrap();

        let stats = renderer
            .begin_frame(FrameInput::default())
            .unwrap()
            .finish()
            .unwrap();

        assert_eq!(stats.memory.backend_retirement.tombstones, 0);
        assert!(stats.memory.backend_retirement.last_poll_queue_empty);
        assert!(
            stats
                .memory
                .backend_retirement
                .retired_after_queue_empty_poll
        );
        assert!(
            !stats
                .memory
                .backend_retirement
                .last_poll_completed_submission_index_recorded
        );
        assert!(
            !stats
                .memory
                .backend_retirement
                .retired_after_completed_submission_index_poll
        );
        assert!(
            !stats
                .memory
                .backend_retirement
                .retired_all_tombstones_had_submission_index_this_poll
        );
        assert!(
            stats
                .memory
                .backend_retirement
                .retired_no_tombstones_had_submission_index_this_poll
        );
        assert_eq!(
            stats
                .memory
                .backend_retirement
                .retired_tombstone_submission_index_coverage_this_poll,
            TombstoneSubmissionIndexCoverage::None
        );
        assert_eq!(
            stats
                .memory
                .backend_retirement
                .retired_shader_variant_modules_this_poll,
            1
        );
        assert_eq!(
            stats
                .memory
                .backend_retirement
                .retired_fence_objects_this_poll,
            1
        );
        assert_eq!(
            stats
                .memory
                .backend_retirement
                .retired_fence_submission_indices_this_poll,
            0
        );
        assert_eq!(
            stats
                .memory
                .backend_retirement
                .retired_fence_objects_without_submission_index_this_poll,
            1
        );
        let capture = stats.capture.as_ref().expect("capture data is attached");
        let capture_dump = capture
            .resource_dump
            .as_ref()
            .expect("capture resource dump is attached");
        assert_eq!(
            capture_dump
                .backend_retirement
                .retired_fence_objects_without_submission_index_this_poll,
            1
        );
        assert!(capture_dump.backend_retirement.last_poll_queue_empty);
        assert!(
            capture_dump
                .backend_retirement
                .retired_after_queue_empty_poll
        );
        assert!(
            !capture_dump
                .backend_retirement
                .retired_all_tombstones_had_submission_index_this_poll
        );
        assert!(
            capture_dump
                .backend_retirement
                .retired_no_tombstones_had_submission_index_this_poll
        );
        assert_eq!(
            capture_dump
                .backend_retirement
                .retired_tombstone_submission_index_coverage_this_poll,
            TombstoneSubmissionIndexCoverage::None
        );
        let report = renderer.frame_debug_report().unwrap();
        assert!(report.memory.backend_retirement.last_poll_queue_empty);
        assert!(
            report
                .memory
                .backend_retirement
                .retired_after_queue_empty_poll
        );
        assert!(
            !report
                .memory
                .backend_retirement
                .retired_all_tombstones_had_submission_index_this_poll
        );
        assert!(
            report
                .memory
                .backend_retirement
                .retired_no_tombstones_had_submission_index_this_poll
        );
        assert_eq!(
            report
                .memory
                .backend_retirement
                .retired_tombstone_submission_index_coverage_this_poll,
            TombstoneSubmissionIndexCoverage::None
        );
        assert_eq!(
            report
                .memory
                .backend_retirement
                .retired_fence_objects_without_submission_index_this_poll,
            1
        );
        assert_eq!(renderer.memory_stats().backend_retirement.tombstones, 0);
    }

    #[cfg(feature = "backend-wgpu")]
    #[test]
    fn facade_scene_can_build_legacy_render_scene() {
        let mut renderer = Renderer::new_headless(RendererConfig::default());
        let vertex_layout = VertexLayout {
            streams: vec![VertexStreamLayout {
                stride: 32,
                step: VertexStepMode::Vertex,
                attributes: vec![
                    VertexAttribute {
                        semantic: VertexSemantic::Position,
                        format: VertexFormat::Float32x3,
                        offset: 0,
                    },
                    VertexAttribute {
                        semantic: VertexSemantic::Normal,
                        format: VertexFormat::Float32x3,
                        offset: 12,
                    },
                    VertexAttribute {
                        semantic: VertexSemantic::TexCoord(0),
                        format: VertexFormat::Float32x2,
                        offset: 24,
                    },
                ],
            }],
        };
        let mut vertices = Vec::new();
        for (position, uv) in [
            ([0.0_f32, 0.5, 0.0], [0.5_f32, 0.0]),
            ([-0.5, -0.5, 0.0], [0.0, 1.0]),
            ([0.5, -0.5, 0.0], [1.0, 1.0]),
        ] {
            for value in position {
                vertices.extend_from_slice(&value.to_le_bytes());
            }
            for value in [0.0_f32, 0.0, 1.0] {
                vertices.extend_from_slice(&value.to_le_bytes());
            }
            for value in uv {
                vertices.extend_from_slice(&value.to_le_bytes());
            }
        }
        let mesh = renderer
            .create_mesh(MeshDesc {
                label: Some("triangle"),
                vertex_layout,
                vertices: VertexData::Interleaved(&vertices),
                indices: Some(IndexData::U16(&[0, 1, 2])),
                submeshes: vec![SubMeshDesc {
                    index_range: 0..3,
                    vertex_range: 0..3,
                    material_slot: 0,
                    bounds: test_bounds(),
                }],
                bounds: test_bounds(),
                usage: MeshUsage::STATIC,
                flags: MeshFlags::default(),
                skin: None,
                morph_targets: Vec::new(),
                meshlets: None,
            })
            .unwrap();
        let texture = renderer
            .create_texture(TextureDesc {
                label: Some("white"),
                dimension: TextureDimension::D2,
                width: 1,
                height: 1,
                depth_or_layers: 1,
                mip_levels: 1,
                samples: 1,
                format: TextureFormat::Rgba8UnormSrgb,
                usage: TextureUsage::SAMPLED,
                initial_data: Some(TextureInitialData {
                    bytes: &[255, 255, 255, 255],
                    bytes_per_row: 4,
                    rows_per_image: 1,
                }),
            })
            .unwrap();
        let material = renderer
            .create_standard_material(StandardMaterialDesc {
                label: Some("standard".to_owned()),
                domain: MaterialDomain::Opaque,
                base_color: Color::WHITE,
                base_color_texture: Some(texture),
                normal_texture: None,
                metallic_roughness_texture: None,
                occlusion_texture: None,
                emissive_texture: None,
                metallic: 0.0,
                roughness: 0.5,
                emissive: Vec3::ZERO,
                alpha_mode: AlphaMode::Opaque,
                double_sided: false,
                receive_shadows: true,
                cast_shadows: true,
            })
            .unwrap();
        let environment = renderer
            .create_environment(EnvironmentDesc {
                label: Some("studio".to_owned()),
                skybox: Some(texture),
                irradiance: None,
                prefiltered_specular: None,
                brdf_lut: None,
                intensity: 0.8,
                rotation: Quat::IDENTITY,
                diffuse_color: Color::WHITE,
                diffuse_intensity: 0.4,
                specular_color: Color::WHITE,
                specular_intensity: 0.8,
                texture: Some(texture),
                background_intensity: 0.2,
            })
            .unwrap();
        let scene = renderer
            .create_scene(SceneDesc {
                label: Some("scene".to_owned()),
                max_objects_hint: None,
                max_lights_hint: None,
                enable_gpu_culling: false,
                enable_occlusion_culling: false,
            })
            .unwrap();
        renderer
            .edit_scene(scene, |scene| {
                scene.spawn(RenderObjectDesc {
                    mesh,
                    materials: vec![material],
                    ..RenderObjectDesc::default()
                });
                scene.set_environment(Some(environment)).unwrap();
            })
            .unwrap();
        let view = ViewDesc {
            label: Some("view".to_owned()),
            scene,
            camera: CameraDesc {
                label: Some("camera".to_owned()),
                transform: IDENTITY_MAT4,
                projection: Projection::Perspective {
                    vertical_fov: 1.0,
                    aspect: 1.0,
                    near: 0.1,
                    far: Some(100.0),
                    reverse_z: false,
                },
                exposure: Exposure::Auto,
                clear: ClearOptions::ColorDepth(Color::BLACK),
                viewport: None,
                scissor: None,
                jitter: None,
                previous_view_proj: None,
                flags: CameraFlags::MAIN,
            },
            target: RenderTarget::MainSurface,
            render_path: RenderPath::Forward,
            quality: ViewQualitySettings {
                hdr: false,
                bloom: false,
                taa: false,
                fxaa: false,
                ssao: false,
                ssr: false,
                depth_of_field: false,
                motion_blur: false,
                variable_rate_shading: false,
                bindless_textures: false,
                mesh_shaders: false,
                virtual_texturing: false,
                ray_tracing: false,
                color_grading: ColorGradingMode::None,
            },
            layers: RenderLayerMask::all(),
            graph_extensions: Vec::new(),
        };
        let legacy = renderer.build_legacy_scene(&view).unwrap();
        let queue = engine_render::RenderQueue::from_scene(&legacy);

        assert_eq!(queue.stats().item_count, 1);
        assert_eq!(queue.stats().draw_call_count, 1);
        assert_eq!(legacy.mesh_entries().count(), 1);
        assert_eq!(legacy.texture_entries().count(), 1);
        assert_eq!(legacy.lighting().environment.diffuse_intensity, 0.4);
        assert_eq!(legacy.lighting().environment.specular_intensity, 0.8);
        assert_eq!(legacy.lighting().environment.background_intensity, 0.2);
    }

